if(window.location.hostname!=='vedic-traditions.github.io'&&window.location.hostname!=='localhost')throw new Error("Access denied"); const chertogDescriptions = { "7.stork": " Чертог Бусла (Лелеки).\n\nЛюди, народжені під знаком Бусла (Лелеки), ніжні, в міру емоційні та поступливі. Вони завжди намагаються підтримувати порядок не лише в домі, а й у власних думках, поточних справах і особистих стосунках. За натурою вони спокійні та миролюбні, але якщо їм постійно хтось заважає досягти своїх цілей, Бусл цього не терпітиме і чинитиме гідний опір. Вони надають особливого значення сімейним цінностям, готові на самопожертву заради збереження та покращення сім'ї. Люди, які народилися в цей період, дуже працьовиті. Все, що у них є в житті, — це результат їхньої праці. Вони чуйні, і за першим покликом поспішають на допомогу близьким. Вони можуть зберігати знання, тому вони можуть стати службовцями в історичних фондах чи архівах, хранителями родовідних книг. Особливо добре люди Чертога Бусла здатні зберегти знання та традиції свого роду, повністю передати їх наступним поколінням. Недарма Чертог названий на честь лелеки — птаха, який славиться своєю вірністю дому, родині, пташенятам і партнеру, що обирається раз і на все життя.\n\nТакож лелеки-люди відзначені як міцні господарники та чудові сім'янини. Опис їхнього характеру дуже подібний до цього миролюбного птаха. Їм властиво віддати свої почуття раз і назавжди одному партнеру, якому зберігають вірність до кінця днів. Лелеки славляться своїм ставленням до дітей, яких народжують велику кількість, бо вони бачать сенс продовження своєї крові, роду. У Чертозі Бусла зазвичай народжуються ті, хто відрізняється неймовірним людинолюбством і поступливим характером. До того ж, у Буслів завжди відкрите, чуйне серце, що змушує їх піклуватися про оточуючих, з любов'ю ставитися до природи та будь-якої живності, яка її населяє. Напевно, тому серед Буслів буває мало воїнів, загарбників. Їм властиві вчинки, що приносять мирні плоди — землеробство, мистецтво, розвиток науки. Особливо, в чому лелеки процвітають, це творчість — малювання, рукоділля. Їхній тонкий внутрішній світ здатний вловити красу світобудови, яка іншим не видна і не підвладна осмисленню.\n\nЦі люди, як правило, неймовірно розумні, мають гострий погляд, від якого не приховається жодна деталь. Вони добре розбираються в людях, немов за інтуїцією відчувають суть людську, навіть те, що приховано глибоко в душі і не показується чужинцям. Їх складно обдурити, тому що обман вони здатні розпізнати за поглядом і зітханнями — настільки сильна інтуїція Буслів. У народжених у Чертозі Лелеки добре розвинена власна мотивація для досягнення цілей.\n\nЧоловіки, які народилися в Чертозі Бусла, є вірними друзями, готовими прийти на допомогу в будь-яку хвилину, вони ніколи не забувають добра. Цих чоловіків не можна назвати впертими, але вони цілеспрямовані настільки, що іноді це заважає їм побачити найпростіші шляхи вирішення найпростіших питань.\n\nЖінки, які народилися в Чертозі Бусла, вміють знаходити «хороші місця» для розвитку свого Роду. Найчастіше у цих жінок щаслива і міцна сім'я, здорове потомство. Вони дбайливі господині, люблять і вміють вести домашні справи, клопотатися по дому, облаштовувати своє житло. Жінки Чертога Бусла, як правило, багатодітні, вони дуже сильні та витривалі, завжди поспішають на допомогу тим, хто слабший за них і потребує захисту.\n\n Бог Покровитель.\nРод — верховний Бог-Творець у слов'янській традиції, прародитель усього живого, творець трьох світів: Прави (небесного), Яви (земного) та Нави (потойбічного). Він вважається творцем всесвіту, первісною силою, яка розділила світло і темряву, а також покровником сім'ї, роду та продовження життя, від якого походять слова «природа», «родина» (батьківщина).\n\n Священне Дерево.\nДерево, яке Лелеки вважають тим, що дає їм силу — верба. Для східних слов'ян верба вважалася особливим деревом. Верба — дерево емоцій, що дає широкий спектр почуттів, переживань тим, кому вона протегує. Духом верби прийнято було підживлювати свої життєві сили і просити у неї заступництва в разі душевних і серцевих мук. У цього дерева просили допомоги та підказки, задумавши якусь справу. Також із вербової деревини Лелеки робили собі оберіг, на якому зображували руну, що позначає Чертог Бусла, відповідно до рунічних зображень, які відповідають конкретним знакам Сварожого кола. Силу, яку дає верба, не можна назвати доброю — цьому дереву проблеми добра і зла абсолютно байдужі. Його сила служить тільки природі, єдиний закон, що має владу над вербою, — закон рівноваги та справедливості. Посадіть вербу в саду, найкраще на березі струмка або річки. Це забезпечить винятково ефективний захист вашого будинку від злих сил. Носіть із собою гілки цього дерева, щоб позбутися страху перед смертю. Зав'яжіть на тонкій гілці верби вузол. Це стане матеріальним символом ваших намірів при заклинаннях. Якщо ваше бажання здійсниться, розв'яжіть вузол. Збережіть гілку для наступних заклинань.\n\n Священні камені.\nКаменями-оберегами для Чертога Бусла (Лелеки) традиційно вважаються натуральні камені, що сприяють гармонії та захисту: обсидіан, нефрит, лазурит (ляпіс), халцедон і чорний агат. Ці камені допомагають представникам чертога зберігати душевну рівновагу та приносять удачу.", "6.bear": " Чертог Ведмедя.\n\nЛюди, що народилися в цьому Чертозі, - добрі і уважні до оточуючих. Вони наполегливо йдуть до своєї головної мети – ушляхетнити все навколо себе. Вони вміють розпочати справу з нуля та довести її до завершення. Маючи чудову фантазію, вони можуть стати творцями, винахідниками чогось нового як у галузі науки, так і в мистецтві. Притаманні їм риси характеру - хоробрість та мужність.\nЧертог Ведмедя – той час, коли народжуються дуже позитивні, добрі люди. Їх характер, немов із ниток, зітканий із кохання, добра і турботи. Ведмідь, як ясно сонечко, може своєю появою осяяти, бо немає людини, якій він приносить погане.\nЗ дитячої пори у Ведмедів проста, легка вдача, що прагне до знань. Вони неймовірно розумні та наділені величезним потенціалом розвитку.\nДуже старанні до наук, тому здатні досягати яскравих результатів у майбутньому. Але, варто врахувати - їх найголовнішим ворогом є лінощі. Як і сам символ чертога, Ведмідь вносить у характер підопічних свою відому особливість – впадати у сплячку. У людях така риса не має ознак сезонності, вона, на жаль, переслідує їх постійно. Якщо ведмеді зможуть подолати свій недолік, то завжди зможуть поліпшити свої досягнення.\nКоли головою сімейства є чоловік чертога Ведмедя, така сім'я обов'язково процвітатиме, причому - у всіх сферах: і в матеріальній, і в духовній, і щодо потомства. Чоловіки Ведмеді мужні та стійкі, вони не поступаються життєвим обставинам, хоча зовсім не обов'язково сильні фізично. Їхня міць - у внутрішньому духовному стрижні, який неможливо зламати.\nЖінки, що народилися в Чертозі Ведмедя, докладають максимум зусиль, щоб їхня родина була благополучною і нічого не потребувала. Вони прагнуть покращити не лише світ навколо, а й себе. Жінки чертога Ведмедя відповідальні та обережні у всьому: і у виборі супутника життя, і у побудові ділових відносин, і в питаннях виховання дітей. Така вдумливість дозволяє їм не робити безрозсудних вчинків, а також завжди бути впевненими у власній правоті. Жінки Ведмеді дуже дбайливі та добрі, вони уважні до оточуючих. Отримавши прихильність такої жінки, можна завжди розраховувати на її допомогу та розуміння.\n\n\n Народженим у чертогі Ведмедя передається вся сила цієї священної тварини.\n\nБог Покровитель.\nЗаступається за нього творець твердої земної та всесильної думки – Сварог. «Іпатіївський літопис» порівнює Сварога з Гефестом – богом-ковалем.\nВін символ світопорядку. Коли приходить війна, бог-трудівник і творець здатний взяти в руки свій молот і розтрощити ворога. Чертог Ведмедя присвячений тварині, що символізує давніх слов'ян. Наші славні предки, подібно до свого деміурга Сварога, здатні були трудитися і отримувати благодатні плоди від вирощування ріллі.\nАле коли ворог ступає на землю батьків, то всяка слов'янська людина перетворюється на безстрашного воїна, що розбиває всяку нечисть. Так і ведмідь - тварина мирна, поки її не зворушать злом.\nВселяючи у своїх підопічних могутню силу, Сварог наділив їх величезним люблячим серцем, щоб утихомирити їхню міць і направити її в русло творіння. Однак основною турботою цього божества було заступництво над працею. Бо ім'я Сварог походить від слова «зварганити», що означає створити, створити.\nТому першою турботою цього божества було, є і буде заступництво мирній творчій праці, яка робить світ Яві кращою і зручнішою.\n\n Символ божества - коваль, що висікає іскри молотом, з яких одержують вогонь. Адже вогонь – це велика сила, здатна як руйнувати, так і дарувати світло та тепло.\n\nСвященне Дерево.\n\n Чертог Ведмедя у слов'янському гороскопі перебуває під заступництвом бога Сварога. Його священними деревами вважаються бук (символ мудрості, достатку та стійкості) та малина. Оберіг з буком допомагає людям цього чертогу здобути впевненість, мужність і удачу у справах.\n\nСвященне Каміння.\n\nЧертог Ведмедя у слов'янському гороскопі символізує силу, стійкість і мудрість; його покровителем є бог Сварог, а священним деревом — бук. Основними оберегами є натуральний кіготь або ікло ведмедя, що захищають від злих сил, привертають удачу та здоров'я. Камені — аметист, цитрин, кремінь.", "10.bull": " Чертог Тура (Бика).\n\nЧертог Тура - знак Сварожого кола, що увібрав всю мудрість і спокій тварини Тура (Бика), який дав чертогу своє ім'я. Над народженими під знаком Тура панує і дбає бог Кришень. Цей бог зберігає Всесвітню вікову Мудрість, Верховний план буття. Під заступництвом Кришеня знаходяться всі арійські та слов'янські обряди, від нього передаються людям знання про прикмети – закони взаємодії матерії в Яві. А надихає своїм духом дерево Осина – дерево руйнування зла, поглинання негативної енергії. Люди цього періоду – ідеалісти за світоглядом, мають підвищене почуття відповідальності. Їх відрізняє підвищена працездатність, але захоплюючись творінням, вони часто забувають про рідних та близьких. Ці люди можуть багато чого досягти, оскільки мають завидну завзятість і працьовитість. Вони здатні щось винаходити, проектувати різні механізми.\nТури, як і тварина, що дає їм назву, напрочуд завзяті і працелюбні. Вони ніколи не поспішають, але водночас вкрай вдумливо та обережно рухаються до наміченої мети. Турам властива чудова організація, вони продумують до дрібниць свої кроки та дії. Одне може затьмарити їхній настрій – залежність від природних процесів змушує зазнавати перепадів тиску. Здоров'я Турів часто страждає від стрибків тиску або меланхолії, які вибивають їх з активного життя.\nТури часто інтроверти, вони не люблять величезні скупчення людей, їм властиво дружнє споглядання суспільства, але без активної участі у соціумі. Вони віддають перевагу вузькому колу перевірених друзів замість галасливого натовпу, який їх дуже швидко втомлює. Бо ті розумові процеси, які постійно відбуваються у цих мудреців, не зазнають суєти та перешкод.\nНароджені в Чертозі Тура відрізняються напрочуд спокійною вдачею. Вибираючи супутника життя, створюючи сім'ю, вони намагаються виважено підійти до такого серйозного вчинку. Їхня половинка також повинна відрізнятися спокійною вдачею, мати доброту і мудрість для створення матеріальних благ. Сімейне гніздо для Турів - фортеця, яку вони свято бережуть від стороннього посягання та вторгнення непроханих гостей.\nВони дуже люблять своїх чад, яким віддають весь вільний від творіння та праць праведних час. У них розчиняються всією душею і помислами, у них бачать привід для розчулення і радості, бо своя кровиночка для Турів - світло, сяйво, промінчик щастя. Тури дуже розумні з наймолодшого віку, з роками лише посилюють свій потенціал. Їм властиво глибоко осягати всі мислимі знання, що дають людям науки.\nЗазвичай вони мають хороші здібності домогтися як матеріальних успіхів, а й зайняти у суспільстві авторитетні позиції. До їхньої думки та порад прислухаються широкі маси народу, тому що покрив мудрості на світлій главі Турів сприяє довірі та повазі.\nЧоловіки, що народилися в Чертозі Тура, відрізняються мужнім та відважним характером. Якщо вони щось роблять, то прагнуть досконалого, максимально ідеального результату. Це відмінні виконавці та вірні друзі. Саме тому чоловіки Чертога Тура часто обирають професію військового чи рятувальника. Чоловік-Тур нагадує могутню скелю: він нерухомий, поки його не чіпають, але зрушити його зі шляху практично неможливо. Тур не шукає легких шляхів і не вірить у «удачу з повітря». Він готовий методично, щодня, будувати свій добробут. Це люди, у яких тримається будь-яка структура. Незважаючи на величезну внутрішню силу, Тур рідко виявляє агресію першим. Він добродушний, спокійний і навіть трохи повільний у прийнятті рішень, оскільки ретельно все зважує. Для нього «правильно» важливіше, ніж «вигідно». Якщо він бачить несправедливість, його гнів буде нищівним. Тури вшановують традиції, поважають старших і важко приймають різкі зміни. Їм важливий ґрунт під ногами. Жінка поряд з ним почувається у повній безпеці. Він перебирає всі важкі завдання: від забитого цвяха до забезпечення фінансової стабільності. Упертість – головна проблема у спілкуванні з ним. Якщо Тур щось убив собі на думку, переконати його логікою чи сльозами майже неможливо. Йому потрібен час, щоб «пережувати» інформацію і самому дійти нового висновку. Під зовнішньою суворістю ховається дуже ніжна натура. Він цінує домашній затишок, смачну їжу та тілесний комфорт.\nЖінки, що народилися в Чертозі Тура, прагнуть нових знань і вміють передавати їх іншим людям. Тому вони часто реалізують себе у викладацькій діяльності чи вихованні дітей. Їхня цілеспрямованість і відповідальність дають можливість досягти приголомшливих результатів на цій ниві. Жінки чертога Тура особливу увагу приділяють стосункам у сім'ї та трепетно ​​оберігають будинок. Вони мають усі якості для створення ідеальних умов для гармонійного існування. Вони вірні, люблячі дружини, і ніколи не дозволять собі зрадити чи обдурити кохану людину.\nЛюди з чертога Тура мають завидну завзятість і працьовитість.\n\n Бог Покровитель.\n\nБог Кришень - одне з імен слов'янського Бога. Трапляються також інші інтерпретації його імені. Кришань, Кришн - у західних слов'ян, Кресень або Кришень - у північних слов'ян.\n\n Священне Дерево.\n\nДерево дивовижної сили, здатне бороти чаклунство без залишку. Потрапляючи під покрив тремтячого листя осики, всяке зло і магія втрачали свої здібності. Своїм підопічним осика часто давала можливість захищати людей від будь-якого магічного дійства, тому часто Чертог Тура дарував людям волхвів, наділених знаннями та здібностями протистояти Нав'їм підступам (Нав - темрява, смерть, темна сторона життя, Яви).\nЩоб поповнити свої сили і особливо очистити ауру від зла, заздрісних поглядів, псування, Турам достатньо було притиснутися всім тілом до своєї натхненниці — осики.\nНароджені під знаком з такою покровителькою завжди легко могли позбутися будь-якої наведеної хвороби. Осика здатна забирати, знімати з людини всяку недугу і нести її в землю через своє коріння.\nСеред Турів дуже багато тих, хто, взаємодіючи з силами природи, причому не завжди хорошими, ризикує отримати магічний удар, бо дуже чуйний до будь-яких енергій та явищ. У такому разі натхненниця осика допоможе, будучи талісманом. Найкращий оберіг для Туру роблять із осикової деревини.\nСпілкування з осиною допомагає при нервових станах, нав'язливих думках, безпричинному страху. У магії осика вважається деревом, яке відводить смерть. Вона сприяє прояву внутрішніх лікувальних сил людини, що забезпечує доступ до нашої справжньої сутності, іноді прихованої під оманливою зовнішньою оболонкою. Однак надто довго контактувати з нею не варто, можна втратити багато корисної енергії.\nОсика, посаджена у саду чи полі, оберігає від злодіїв.\n\n Священне Каміння.\n\nКамені чертогу Тура покликані посилювати працьовитість, стійкість і душевну теплоту, властиві людям цього знака. Основними обережними мінералами вважаються смарагд, агат (особливо білий) та кахолонг, які допомагають приймати виважені рішення та зберігати внутрішню гармонію.", "15.white leopard": " Чертог Раса (Рись, Білий Леопард).\n\n\nЛюдей чертога Раса (Рисі, Білого Леопарда) відрізняє цілеспрямованість та розважливість. Однак при цьому вони не завжди здатні брати до уваги думку іншої людини. Вони можуть цінувати те, що дано зверху. Ці люди з раннього дитинства усвідомлюють свою особливу силу та унікальність. Однак вони не повинні забувати про шанобливе ставлення до Бога і матері-природи, які, власне, і є для них головним джерелом життя та енергії. Разом із веселою вдачею та безтурботністю люди чертого Раса виявляють спокій та розважливість у момент розгляду важливих питань.\nЧоловіки, що народилися Чертозі Раса, відповідально ставляться до своїх робочих обов'язків, вони прагнуть виконувати все якісно і вчасно. Їм можна довірити вирішення будь-яких завдань, вони зроблять максимум і обов'язково досягнуть поставленої мети. Для них немає непереборних перешкод, це стійкі та відважні люди. Негативною рисою деяких чоловіків Чертога Раса є егоїстичне ставлення до оточуючих. Вони можуть у цьому сенсі «йти по головах», коли вважають, що обрана ними ціль виправдовує будь-які засоби. Однак через це вони можуть втратити авторитет і повагу у суспільстві, що зрештою призведе до самотності.\nЖінки, що народилися в Чертозі Раса, позитивні, відкриті та життєрадісні. Їх можна легко впізнати по задерикуватому сміху та оптимістичному настрою. Вони ніби світяться зсередини і здатні передавати свій настрій оточуючим. Іноді вони здаються безрозсудними, але насправді мають життєву мудрість і розважливість. Наділені від природи різноманітними талантами жінки Чертога Раса можуть реалізувати себе в різних сферах, постійно демонструючи відповідальність, старанність і відмінні результати. Чертог Раса наділяє своїх підопічних дуже живим та імпульсивним характером. Раси можуть швидко загорятися цікавою ідеєю, захоплюватися новим заняттям чи справою, але, не бачачи конкретної мети, можуть швидко перегоряти, згортати свою активність. Іноді навіть занепадає через те, що не можуть досягти великих результатів. Біда в тому, що Раси не можуть чітко артикулювати ту мету, до якої прагнуть, але це змушує їх блукати шляхом до неї, віддаляючись від успіху. Адже чіткий план – половина перемоги. Але характер Раси настільки широкий і шляхетний, що по дорозі до намічених вершин він намагатиметься звалити на себе чужі турботи і турботи, допомагати знедоленим або скривдженим, а своя мета так і залишиться далеко недоступною Рисі-Леопарду у житті. Мудрість Раса завжди користується заслуженою повагою з боку суспільства. Він не набуває ніколи слави сластолюбця чи скнари. Леопард отримує те, що сіє – доброту, людинолюбство, щедрість та відвагу.\n\n Однією з найсильніших якостей, яким наділяє Чертог Раса, – сміливість. Це чертог тих, хто народжений із духом воїна-захисника. Ця якість ніколи не вживається на зло. Вона сидить у душі Раси тихо, рівно доти, доки потрібно стати на захист слабкого та скривдженого. Але якщо ця відважна людина стикається з несправедливістю, підлістю чи іншим проявом зла, то дух воїна одразу прокидається і дає смертний бій. Іноді їхня добра вдача вводить недоброзичливця в оману і викликає бажання випробувати на Расі свою підлість, але це жорстоко припиняється і карається Леопардом. Їхня відповідь нахабства буде блискавичною і нищівною, Раса не дозволить грати з собою. Дуже часто Раси є одночасно розумними та рішучими людьми. Їхній відмінний набір якостей рано чи пізно стає запорукою того, що вони піднімаються на вершину влади або набувають величезного авторитету в соціумі. Таких людей часто можна зустріти в іпостасі керівників, лідерів, які ведуть великі громади. Один із зовсім небагатьох недоліків - лінь. Ось з нею Расам слід боротися більше, ніж із зовнішнім ворогом, тому що вона буває їх найлютішим ворогом. Від того, наскільки успішно Леопард поборе цю підступну лиходійку, залежать ті плоди, яких він здатний досягти.\n\nБог Покровитель.\n\n Бог Тарх-Даждьбог. Сварожич є Богом-Покровителем та уособленням Златого Сонця в Чертозі Раси на Сварожому Колі. Наші пращури вірили, що Даждьбог дбає про весілля, зустрічає нареченого на світанку в день Освячення Сімейного Союзу, тому й казали, що Весілля відбуваються на Небесах і освячуються Дажбогом - Сонцем. Був названий Даждьбогом (що дає Богом) за те, що дав людям Великої Раси та нащадкам Роду Небесного Дев'ять Саньтій (Книг).\n\nСвященне Дерево.\nЯсен уособлює собою мудрість поколінь і ясність розуму. Згідно з історичними писаннями, листя і гілки дерева живляться небезпечною енергією, завдяки чому мають чудодійні магічні властивості. Гілки священного дерева простягаються високо в небо, а коріння сягає найважливіших витоків: до богів руських, до первонароджених людей. Ясен - це дерево відродження та оновлення. Крім того, ясен уособлює зв'язок того, що нагорі, з тим, що внизу, тобто зв'язок світу богів та світу людей або світу духовного та матеріального. Ясен зазвичай у міфології символізує Світове дерево чи Древо життя; у норвезьких міфах ясен був присвячений верховному богові Одіну; його називали Іггдрасіл; він був джерелом життя та безсмертя; крона, стовбур і коріння з'єднували підземний світ, землю та небеса.\nЯсен – дерево величезних можливостей. Воно наділяло своїх підопічних силою впливати та взаємодіяти з енергіями Всесвіту. Такі люди найчастіше мали здібності до ясновидіння, чаклунства та передбачення. А вплив Раси, благородного звіра, посилювало потяг людини робити добрі вчинки, використовуючи дар вищих. Бо унікальні можливості магічної сили могли бути привабливими для тих, хто хотів шкодити. Руна Раса, взаємодіючи з ясенем, мала величезне захисне значення свого підопічного.\n\n Гілки ясеня, повішені над вхідними дверима, оберігають від злих сил, а пояс, зроблений із зеленої кори, служив захисним засобом проти магів та чарівників. Для захисту будинку та прилеглої ділянки розкидайте листя ясена на чотири сторони. З цією ж метою вони використовуються в мішечках та при здійсненні магічних дій. З іншого боку, особлива магія традиційно приписується вогню, розпаленому на ясеневых дровах. Дим такого вогнища вважається священним курінням, а сила, що виходить від вогню, - благотворною і цілющою.\n\nСвященне Каміння.\n\nОсновним каменем-талісманом для Чертога вважається бурштин. Цей натуральний камінь ідеально підходить представникам чертога, оскільки символізує сонячну енергію, родючість і мудрість, допомагаючи розкрити їхній потенціал, працьовитість і життєлюбність, а також слугує сильним оберегом.", "12.falcon": " Чертог Фініста.\n\nЧертог Фініста – знак у зодіакальній системі праслов'ян. Своє ім'я отримав на честь міфологічного птаха Фініста, який був символом відродження, вічної молодості та безсмертя. У слов'янських казках цей птах носив ім'я Фініст-Ясний Сокіл. Його описували, як птаха з палаючим оперенням червоного і вогненно-золотого кольору, якого неможливо було вбити, у нього була властивість знову відроджуватися з попелу і перемагати будь-яку підлість, зло і чаклунство. Іноді цей міфічний персонаж міг приймати образ молодого хлопця, який приходив у Яв і захищав пригноблених і скривджених людей. Повертав їм віру в добро та справедливість. Ім'я Фініст-ясний сокіл у слов'янській міфології пов'язується з молодим чоловіком напівбожественного походження, який завжди з'являвся у найгостріші моменти нещасть та нападів ворогів. Ці риси – активність, боротьба за справедливість, принциповість, твердість у своїх принципах, а водночас неймовірне життєлюбство та добре розвинений гумор, дістаються народженим під знаком Фініста. Вони, немов той міфічний птах, навіть зустрівши на своєму шляху небезпеку, не сумують, а активно долають перешкоду і не втрачають присутності духу. Своє ім'я цьому чертогу підходить як ніяке інше – вічна боротьба та вічне життя. Хоча назва священного дерева Фініста – Вишні та співзвучна імені бога-покровителя Фініста – Вишеня, вони наділяють підопічного кардинально різними властивостями. Від одного Фіністи набувають гострого і проникливого розуму, а від вишні їм дістається романтична, чуттєва натура, дуже весела і активна.\nЛюдей цього періоду відрізняє неймовірна енергія, вони прагнуть робити одразу кілька справ. Їхнім недоліком можна вважати схильність до різких змін настрою. Ці люди мають гарну пам'ять і кмітливість, здатність пом'якшувати конфлікти і розбіжності. Розвиваючи свої сили, вони починають швидко розпізнавати правду та брехню, миттєво розуміючи, коли їх намагаються обдурити. Люди чертога Фініста здатні навчити інших бачити істину навіть за часів загального обману.\nФініст – людина неймовірної активності. Його сил вистачає, щоб замінити цілу спільноту. Такий працівник здатний працювати за трьох, причому здається, ніби він не втомлюється, а дедалі більше захоплюється процесом.\nЦе символ дуже імпульсивних людей, здатних на абсолютно різнопланові вчинки. З одного боку, вони можуть вникати у дуже складні науки, досягати неймовірних висот, можуть заряджати своїм позитивом та оптимізмом. Але з іншого боку, той, хто потрапляє до них у немилість, ризикує пізнати зворотний бік Зоряного Сокола - критику, різкість слів та деяку жорстокість. Фіністам властиво вимагати від людей більшого, ніж слід. Але їх не можна вважати жорстокосердними, їм властиво безкорисливо відгукуватися на заклики про допомогу.\nВ імені Фініста прихований величезний потенціал, що керує людьми на звершення - вчинки, від яких виграє людство. Під впливом чертога Фініста народжуються люди, які прагнуть змінити відразу весь світ. Така активність іноді стає не дуже зручною якістю для тих, хто поруч із ними.\nФіністи ніколи не здаються, володіючи прекрасними аналітичними здібностями, вони вміють планувати та виробляти стратегію досягнення мети. Єдине, що може їх згорнути з обраного шляху – це кохання. Не дарма в російській міфології Сокіл має прообраз молодого хлопця, який, здійснивши ряд подвигів, знаходить свою паву, а потім обов'язково бере за дружину. Це повністю відповідає характеру фіністів – згорнути гори, перемогти зло та одружуватися. Жінки, що народилися в Чертозі Фініста, мають добре розвинену інтуїцію, що підказує їм оптимальні рішення у складних життєвих ситуаціях. Іноді вони можуть здатися навколишнім досить спірними та загадковими натурами, але це оманливе враження. Для близьких та друзів вони завжди відкриті і не намагаються показати себе краще, ніж вони є. Жінки чертога Фініста – обличчя творчі, вони завжди ретельно рухаються до ідеального завершення будь-якої справи.\nЧоловіки, народжені в Чертозі Фініста – це люди неймовірного польоту, оптимізму та невгамовної енергії. Чоловік-фініст – це вічний двигун. Він не може довго перебувати у спокої, його розум і тіло завжди потребують нової мети. Це ті люди, які можуть робити п'ять справ одночасно і при цьому насвистувати мелодію. У них феноменальна швидкість реакції та мислення. Фіністи вірять у високі цілі. Вони часто стають першопрохідниками, дослідниками чи реформаторами, бо їх не влаштовує «як у всіх». Фініст - це міфічний птах (прообраз Фенікса). Як би боляче він не впав, він обтрусить пір'я, витягне урок і злетить ще вище. Рутина йому згубна. Якщо в житті Фініста довго нічого не змінюється, він починає чахнути або сам провокує бурю, щоб струснутись. Він вміє красиво доглядати, робити шалені вчинки та надихати. Жінки часто закохуються у його внутрішню свободу. Незважаючи на влюбливість у юності, зрілий Фініст шукає «ту саму», яка зрозуміє його духовні пошуки. Якщо він її знаходить, він захищатиме її інтереси лютіше за будь-який інший знак. Із дітьми він на одній хвилі. Він швидше піде з ними в похід або навчить запускати ракети, ніж перевірятиме уроки за столом. Завдяки заступництву Вишня, вони можуть стати глибокими філософами чи коучами.\nЯкщо чоловік-Фініст – це стрімкий сокіл, то жінка чертога Фініста – це справжня чарівниця, наділена неймовірною інтуїцією та здатністю бачити світ у яскравих фарбах. Така жінка живе почуттями та осяяннями, вона легка на підйом, але при цьому має стрижень, який не дає їй зламатися під тягарем обставин. Жінка-фініст - це вічний рух. Вона не терпить застою ні в справах, ні в думках. Навіть у темній смузі життя вона знайде іскру світла. Вона здатна заражати своєю вірою у найкраще всіх оточуючих. Вона не просто робить роботу – вона її «творить». Будь то приготування вечері або написання річного звіту, у цьому завжди буде її унікальний почерк. Їй життєво необхідно змінювати обстановку. Перестановка меблів, новий колір волосся або раптова подорож на вихідні - це її способи перезавантаження. Завдяки Вишню вона часто «знає» речі, які не можна пояснити логікою. Їй сняться пророчі сни, або вона просто відчуває, чи варто довіряти людині. Звичайне сімейне життя «будинок-робота-телевізор» для неї згубне. Вона буде тією дружиною, яка запропонує влаштувати пікнік на підлозі у вітальні або зірватись у гори вночі. Вона не « квочка » . З дітьми вона спілкується як з особистостями, заохочуючи їхні таланти та фантазію. Її діти часто ростуть дуже самостійними та творчими. Їй важливо мати свої інтереси поза сім'єю. Поважаючи її право на «своє небо», чоловік отримає найвірнішу та найцікавішу супутницю.\n\n Бог Покровитель.\n\nБог Вишень є Богом-Покровителем чертога Фініста. Вишень строгий по відношенню до тих, хто прагне спотворити Правду, видаючи Чорне за Божественне. Але при цьому Він добрий до тих, хто дотримується небесних законів Всесвіту і не дозволяє іншим порушувати їх. Він допомагає стійким перемагати у боротьбі з темними силами, які несуть у всі Світи зло та невігластво, лестощі та обман, бажання чужого та приниження однієї живої істоти іншим.\n\n Священне Дерево.\n\nВишня має велике значення у житті людей, як дерево молодості. Своїм весняним кольором, від якого всередині душа розквітає, а серце вистрибує від любові, що навалилася, вишня приносить почуття щастя, найвищого блаженства. Травневе тепло, зелень плавно перетікають під ласкаве червневе сонечко, щоб обдарувати нас червоними плодами з дерева кохання.\nВважалося, що людина, що посадила вишню, отримувала заступництво могутнього Бога Вишеня, у владі якого було не тільки посилати багаті врожаї, берегти здоров'я, вберегти від поганого ока, а й керувати долею і подіями життя людини. Тільки людині творчій, чесній, що йде шляхом освіти і самовдосконалення, він допомагав наповнити душу істинним світлом, серце - зцілюючою любов'ю, а думки - прозрінням.\nМожливо, тому у слов'ян, вишневі дерева садили при вході в новий будинок, весіллі, народженні дитини, вони вірили, що якщо дотримуватись і поважати закони предків, то найважчі моменти можна було просити про допомогу та захист у деревця, посадженого біля будинку.\nІснував звичай, зробити палицю або палицю з вишневого деревця, глибоко вірили, що він має особливу магічну та цілющу силу, що передається від дідуся до батька, від батька до синів. Людина не вмирає, поки вишневі дерева продовжують жити для неї.\nВесною квітучі деревця вишні прикрашали запаленими свічками, а сама вишня вважалася ритуальним деревом новорічного весняного обряду. Якщо замислитися над фразою і припустити, що: «Побудувати будинок, народити сина, посадити дерево» - не просто крилатий вираз чи гіпербола, а саме багатовіковий охоронний ритуал із посадкою вишневого дерева та весь життєвий шлях людини, як у своєму розвитку, так і протягом Роду та самого життя на Землі. Нехай у ваших серцях будь-яку пору року цвіте вишня!\nЯкщо ви стали жертвою енергетичного вампіра або просто втомилися, увімкніть у свій раціон вишню. Вона допоможе вам уникнути втоми та позбутися напруги, а червоний колір вишні – символ гарячої крові та сонячного тепла. Вишні, які ви зірвете своєю рукою на світанку, подарують вам почуття щастя та повноти життя. Якщо ж ви зірвете вишні в ніч, коли Місяць оточений червоною хмарою, то будете все життя прагнути поставленої мети і в результаті досягнете бажаного. Вишня перетворить вас на невразливого для підступів ворогів. До того ж, вона допоможе вам зробити кар'єру.\n\n Священне Каміння.\n\nКамінням-талісманами для чертога вважаються натуральні камені, що сприяють розкриттю талантів, захисту та посилення мудрості. До основних каменів відносяться рубін, смарагд, гранат, агат та гематит. Часто використовуються у поєднанні із срібними оберегами.", "14.eagle": " Чертог Орла.\n\nУ людей Чертога Орла сильно розвинене почуття заступництва і доброзичливість. Ці люди не виявляють слабкості, вони рішучі, особливо коли чітко планують план своїх дій. Вони вміють відбити будь-які атаки: чи то словесні випади на їхню адресу, чи фізичні дії, спрямовані проти них. Людям Чертога Орла корисно займатися практиками на оволодіння силою як у духовній частині, так і у фізичній. Орел вже народжується зі свідомістю своїх сил. Причому це стосується не тільки фізичних, а й інтелектуальних здібностей. Допитливі діти цього чертога змалечку схильні до пристрастей пізнання світобудови. Ними керує ненаситне бажання дізнатися про природу походження будь-яких явищ і предметів. чертог Орла рухає своїх підопічних до нових відкриттів. Орли мають вроджені лідерські якості, але при цьому у них немає місця зарозумілості і пихи. Будучи взірцем сміливості та великодушності, вони з радістю прийдуть на допомогу страждаючим. Рідкісністю для них буває така риса, як меркантильність. Орел не вважає за потрібне відволікатися на матеріальне, вважаючи себе народженим для інших, вищих цілей. Однак саме такий підхід, який не враховує потреби придбання чи отримання благ для себе, стає проблемою у подружньому житті. Хоча найчастіше авторитетність і владолюбство врівноважують цей недолік, маючи на увазі отримання благ іншим шляхом. Але це залежить від багатьох якостей конкретної людини. Кращою парою для Орла стане той партнер, який зможе дрібні побутові проблеми звалити на себе. Бо при здається силі, Орел пасує перед дрібними матеріальними проблемами. Зате він досить вірний та чуйний чоловік, що теж цінно.\nСім'я для Орла - це його фортеця, бастіон, який їм всіляко захищатиметься і оберігатиметься від будь-якого негативного вторгнення. Діти - предмет гордості та надії, на які Орел покладає славу та продовження свого роду. Він їм усіляко допомагає і дбає, перетворюючись поряд з ними на дбайливого і м'якого батька, відданого їм усім серцем. Така ідеальна картина не зовсім точно передає образ народженого в Чертозі Орла. У ті моменти, коли якійсь необачній особі спаде на думку образити його або напасти на його родину, Орел стає відважним захисником своїх близьких. Дух воїна дрімає всередині лише доти, доки не виникне натяк на небезпеку.\nЧоловіки, що народилися в Чертозі Орла, безстрашні та войовничі, люблять спорт, бойові єдиноборства. Однак вони не перетворюють це на самоціль. Вони цінують знання, добре навчаються і здатні вбирати величезні обсяги інформації. У плані побудови особистих стосунків чоловіки Чертога Орла бувають вітряними та вкрай непередбачуваними. З одного боку, вони прагнуть піклуватися про своїх рідних, але з іншого - іноді на них нападає апатія до всього, що відбувається, і тоді навіть наявність сім'ї не зможе сприяти їх поверненню до повноцінного життя. Якщо такий чоловік раптом приходить до висновку, що його життєве правозвання вимагає самотності, то сім'я відходить на другий план. Жінки, що народилися в Чертозі Орла, дуже уважні та дбайливі, вони доброзичливі, розумні та альтруїстичні. Вони люблять допомагати іншим, легко беруть когось під своє заступництво, захищають та дбають. Їхнє справжнє покликання полягає у захисті близьких від усяких бід і непередбачених ситуацій. Вони вміють бути вдячними, на щиру любов відповідають взаємністю, залишаючись відданими своїй другій половинці до кінця днів. Світле почуття кохання жінки чертога Орла готові пронести через всі негоди та мирське життя. Жінка-Орел – це політ над світом з метою контролю та захисту свого простору. Вона рідко сумнівається у своїх рішеннях. Якщо вона поставила за мету, вона піде до неї безпосередньо, не боячись труднощів. У Орлиць дуже розвинене почуття відповідальності за слабких. Вона завжди допоможе, захистить і дасть мудру (хоча іноді й жорстку) пораду. Їй важливо бути авторитетом. Тому вона багато читає, вивчає нове та прагне стати експертом у своїй справі. Орел не вміє плазати. Вона знає собі ціну і не дозволяє оточуючим переходити межі дозволеного. У сім'ї Жінка-Орел – це фундамент. На ній тримається порядок, дисципліна та безпека роду. Вона не вибере слабкого чоловіка. Їй потрібна «рівна», людина честі, яку вона зможе поважати. Незважаючи на свою незалежність, вона вкрай віддана сім'ї. Заради благополуччя близьких вона здатна на будь-які жертви. Її головний мінус – бажання все контролювати. Вона часто «давить» на домочадців своєю опікою, вважаючи, що тільки вона знає, як краще для всіх. З нею складно грати в ігри чи лукавити. Вона віддає перевагу гіркій правді і чекає того ж від чоловіка. Жінка-Орел – природжений керівник чи наставник. Вона розквітає там, де потрібна структура та порядок.\n\n\n Бог Покровитель.\n\nПерун - це Бог-громовержець, Блискавки його зброя, Веселка - його лук, хмари - одяг чи борода і кучері, Грім - Слово, що звучить далеко, вітри і бурі - дихання. Перун - Бог грози та війни.\n\n Священне Дерево.\n\nСвященне Дерево – Дуб. Чертог Орла у покровителях отримав одразу два символи чоловічої сили та доблесті – бога Перуна та дерево дуб. Слід зазначити, що ці вищі сили активно впливають на характер свого підопічного, вносячи до нього лідерські якості, впертість для досягнення цілей, бажання завжди бути переможцем. Дуб - дерево божественної та неймовірної енергетичної сили. Це дерево було ототожненням мощі Перуна. І в далекі часи мала однокореневу назву зі своїм божеством. Але пізніше ім'я бога постаралися забути, так само стерло з пам'яті назву ритуального дерева, його символу та джерела життєвої енергії, що допомагає чоловікові-воїну. Дерево переможців. Йому присвячувалися обряди перед тяжким походом князя з дружинниками. У дібровах проводилися ритуали ініціації, коли в'юнош ставав чоловіком і отримував до рук свою першу бойову зброю. Будь-яке військове спорядження освячувалося під обрядові пісні у головного дуба-оберега\nКожному воїнові слід (і слід) мати при собі частинку дуба у вигляді оберега, щоб воно надавало людині сміливість, впевненість, безстрашність і доблесть. При цьому будь-якому негіднику та клятвовідступнику такий оберіг міг стати покаранням.\nДуб є енергетичним донором. При прямому контакті з ним людина отримує неймовірну кількість життєвої енергії. Але його аура дуже потужна, вона добре сприймає лише здорових людей.\nСпілкування з дубом заряджає людину енергією, що активує, заспокоює душу. Давно помічено, що прогулянки по діброві нормалізують кров'яний тиск, сприятливо відбиваються на роботі серця та нервової системи.\nВважається, що амулет із жолуду забезпечує довголіття, молодість, досягнення та прагнення до мети. Також жолудь сприяє пробудженню енергії та сил молодості.\n\n Священне Каміння.\n\nКамінням-талісманами для чертога Орла, покровителем якого є бог Перун, традиційно вважаються натуральний бурштин, гірський кришталь, малахіт та агат. Ці мінерали відповідають сильній, мудрій та рішучій енергії даного знака, допомагаючи посилити бачення, рішучість та захист.", "2.pike": "Чертог Щуки.\nЧертог Щуки увібрав у себе заступництво відразу двох богородиць: Рожани - богині сімейного достатку та Щуки - цариці річкової та матері водяного духу. Мудрість Одночасно двох божеств займається людьми цього чертога і вносить у характер риси розважливості, доброти і просвітлення. Чертог Щуки отримав свою назву на честь прабатька всього річкового світу.\nОбраз Щуки-чарівниці зберігся до наших часів у міфах та переказах. Широко відома казка про Ємелю та Щуку, яка виконує бажання – яскравий приклад народних оповідей.\nЛюдям, що народилися в цей період, властиве прагнення спокійного, розміреного життя. Основна складність для них – ухвалити важливе рішення. Однак до нових та несподіваних обставин вони легко пристосовуються. Люди чертога Щуки мають здатність ладнати з дітьми, вони добре розуміють поведінку малюків, їхні вчинки та бажання. Гармонія в усьому - у побуті, у душі та свідомості - цього прагнуть ті, хто народився в період Чертога Щуки.\nОднак, за всіх своїх переваг іноді вони можуть бути наївні, надмірно прості і абсолютно беззахисні. У цей час народжуються дуже розумні, добрі та неймовірно терплячі люди. Немов увібрали в себе здібності своєї покровительки Рожани, вони завжди намагаються згладити конфлікт, уникнути сварки, поступитися.\nЯк приклад лагідності, Щуки, проте, не простаки. Їм від природи дано великий дар наук. Причому з раннього дитинства у них не спостерігається особливого прагнення до знань, але осягаючи світ, усвідомлюючи свою роль у ньому, Щуки начебто розкриваються. Згодом вони займають високе становище у суспільстві, бо намагаються і проявляють себе якнайкраще.\nЧертог Щуки наділяє людей не лише допитливим розумом, а й красою. Навіть якщо її не видно з лиця, внутрішній світ Щуки є привабливим і милим. Це ті люди, які обов'язково викличуть симпатію протилежної статі. Вмілі та господарські, вони старанно ведуть будинок. А якщо під знаком Щуки народився чоловік, то він здатний зробити будь-яку жінку щасливою, бо від природи вірний, спрямований на накопичення та заробляння матеріальних благ, обов'язково оточить домочадців теплом та турботою.\nВизначаючи свій земний шлях, Щуки намагаються вибрати той шлях, де можна виявити своє милосердя та турботу. Не гребують добиватися людської слави.\nЧертог Щуки дарує людям дивовижне почуття прекрасного та вміння творити. Серед Щук є справжні таланти лицедійського мистецтва чи умільці, які втілюють красу нашого світу у картинах. Їхній внутрішній світ настільки багатий, що переповнює і прагне публічної оцінки, звідси прагнення втілення у художніх творах. Але мистецтво не єдина сфера, в якій чертог Щуки обдарував свого підопічного талантами. Щука успішно проявляє себе у кожній справі, за яку не візьметься. Природна старанність і проникливість – запорука успіхів. Особливо процвітають там, де потрібно аналізувати, прораховувати. Відмінно справляються у сфері фінансів та множення.\nЧоловіки, що народилися в Чертозі Щуки, особливо щасливі у справах і нових починаннях. Вони відрізняються м'яким, але при цьому завзятим характером. У них присутній непорушний внутрішній стрижень, який допомагає їм досягти успіху практично на будь-якій ниві. Жінки, що народилися в Чертозі Щуки, відрізняються неймовірним прагненням до сімейного благополуччя, вони вміють облаштовувати свій будинок, добре розуміючи значення виразу \"мій дім - моя фортеця\". Вони ревно оберігають затишний будинок від будь-яких посягань ззовні. Жінки чертога Щуки здатні чудово виховати дитину, як свою, так і не рідну їм по крові. Вони можуть народити і виростити дітей, вірних своїй землі та своєму Роду. Народжені в Чертозі Щуки - Гармонія в усьому - у побуті, у душі та свідомості - цього прагнуть ті, хто народився в період Чертога Щуки.\n \n Бог Покровитель.\n\nБогородиця Рожана. (Мати Родиха, Рожаниця). Вічно молода Небесна Богородиця. Богиня сімейного достатку, душевного багатства та затишку. Богородиці Рожані робили особливі жертвопринесення їжею: млинцями, оладками, хлібами, кашами, медом та медовим квасом. Стародавній Слов'яно-Арійський культ Богородиці Рожани, як і інші культи, присвячені Богородицям і Богиням, пов'язаний із жіночими уявленнями про продовження Роду та долю новонародженого немовляти, якому визначається Доля.\n\n Священне Дерево.\n\nНа відміну від інших дерев, які тілом-деревиною допомагають своїм підопічним, слива сильна плодами. Слива плодоносить не тільки найсмачнішими фруктами, але ще й дуже корисними для людини. Унікальний набір елементів здатний допомогти в лікуванні цілого набору тілесних захворювань – від нестачі вітамінів до проблем із серцем та шлунком. До того ж, слива була великою годувальницею у стародавніх народів, які ще не пізнали секретів тривалого зберігання ягід та фруктів. Плоди сливового дерева сушили, в'ялили на спекотному сонці і навіть коптили за часів далекої давнини. Це вміння дозволяло заготувати запаси, які рятували від голоду та допомагали пережити холодну зиму. До того ж, слива - криниця корисних речовин, багата на неймовірну кількість вітамінів і мікроелементів, які були відкриті вченими зовсім недавно, але вже за старих часів допомагали людям зберігати і відновлювати здоров'я.\nГілки сливи, повішені над дверима та вікнами, оберігають будинок від вторгнення злих духів. Сливу їдять для залучення чи збереження кохання. Може допомогти вилікувати страх втрати самоконтролю, запобігти спалаху люті, або якщо ви перебуваєте на межі нервового зриву чи депресії.\n\n Священне Каміння.\n\nЧертог Щуки символізує прагнення спокою, адаптації та сімейного затишку. Як камені-обереги для людей цього чертогу найчастіше рекомендують використовувати перли та корали, пов'язані з водною стихією. Вони допомагають здобути мудрість, врівноважити емоції та захиститися від негативу.\n", "1.boar": " Чертог Вепря.\n\n У цей час народжуються допитливі та наполегливі люди. Їх відрізняє цілеспрямованість та вміння долати перешкоди. Недоліком є ​​здатність не брати до уваги інтереси інших людей. При цьому вони намагаються бути справедливими та рішучими, наполегливо доносити до інших вірність своїх суджень. Вони звикли досягати наміченого, але можуть допускати надто вільну, розкуту поведінку, якщо не будуть тримати себе в руках. Людям Чертога Вепря завжди слід пам'ятати про силу Небесних Законів. Так само як і Вепр - символ відваги та сміливості, народжені в цей час ставали неординарними людьми. Їхня внутрішня сила була важливою частиною їх характеристики. Навіть якщо зовні людині не дано розміри велетня, то завзятість і цілеспрямованість завжди виділяють їх із натовпу.\nЧертог Вепря насамперед наділяє підопічного силою духу. Вепрі, всупереч своєму грізному покровителю, є досить добрими і миролюбними створіннями. Їм не властиво нападати першими чи бити у спину. Вепр - це скоріше символ сплячої могутності. Але якщо назріває потреба, то ця внутрішня енергія набуває неймовірних масштабів, здатних зносити будь-якого ворога, як билинку. Вепрі рідко стають призвідниками та агресорами, частіше їх внутрішній егрегор перебуває у стані мирної свинки - поїсти, поспати, віддатися сибаритству.\nВепрі можуть бути дуже талановитими людьми - схильність до творчості добре простежується у них у характері. Вроджене почуття прекрасного змушує Вепря пропускати навколишній світ через призму естетичного сприйняття. Вони досить критично ставляться до заворушень і хаосу, вимагаючи від свого партнера ідеальності, що межує з досконалістю, що може негативно позначитися на відносинах.\nЧертог Вепря наділяє підопічних чудовими інтелектуальними здібностями. Ці люди завжди на гребені технологічних новинок, вбирають нові знання, постійно множать свій запас ерудиції. Завдяки постійному бажанню вдосконалення та навчання, часто виходять на найвищі щаблі у суспільстві.\nВепрі - часто однолюби. Навіть якщо перше кохання закінчується розлученням, потім Вепрю складно знайти собі пару. Їхнє серце досить болісно переживає моменти розлучення, а рана може довго кровоточити, не даючи шансів іншим почуттям. Лише з віком, зрозумівши якийсь сенс світобудови та накопичивши досвід, Вепрі створюють той досконалий союз, про який мріяли. Йому вони потім віддають весь невитрачений запас кохання, ніжності та опіки, розчиняючись у судженому. Можна сміливо сказати, що пізні шлюби для Вепря - благо.\nЧоловіків, що народилися в Чертозі Вепря, протягом усього життя супроводжує успіх у роботі, особистих відносинах, у нових починаннях. Вони є справжніми борцями за справедливість і готові докласти максимум зусиль, щоб досягти торжества правди над беззаконням. Саме тому багато чоловіків, народжених у період чертога Вепря, схильні вибирати професії, пов'язані з юридичною чи правоохоронною діяльністю. Вони стають успішними адвокатами, затребуваними юристами, добрими поліцейськими чи рятувальниками.\nВепрі від природи сумлінні, на них можна покластися у важкій ситуації, вони мають спокійний і врівноважений характер, мудрість та схильність до творчого мислення. Завдяки енергійному прагненню до поставленої мети чоловіки Вепрі часто обіймають відповідальні керівні посади. Жінки, що народилися в Чертозі Вепря, в першу чергу прагнуть облаштувати будинок, а потім починають планувати своє кар'єрне зростання. Доброзичливість до оточуючих, правдолюбство, розвинене почуття емпатії та бажання допомагати нужденним робить цих жінок справжніми представницями Чертога Вепра. Однак у порівнянні з чоловіками жінки Вепрі відрізняються певною часткою таємничості та скритності, що іноді призводить до надмірної замкнутості. Народжені в Чертозі Вепра - Вепрі можуть бути дуже талановитими людьми - схильність до творчості добре простежується у них у характері.\n\n Бог Покровитель.\n\nБог Рамхат (Ра, Рас, Брама, Рамх, Рама) – Великий Бог справедливого Небесного суду та Вселенського Правопорядку. Він Небесний Суддя, який стежить за тим, щоб не було у Народів Великої Раси і нащадків Роду Небесного порушення кровних заповідей, а також будь-яких заборонених кривавих жертвоприношень, не кажучи вже про людські жертвопринесення. Бог Рамхат спостерігає, щоб життя людей на Землі було відповідно до Законів.\n\n Священне Дерево.\n\nГруша – дерево, що дає гарний настрій. Це дуже важливо для ухвалення будь-яких зважених рішень. Адже дух, що перебуває у сум'ятті, не може об'єктивно сприймати навколишній світ. Щоб не трапилося, не впадайте в паніку – медитація в тіні крони дерева здатна збалансувати енергетичні потоки всередині та поза людиною. Усі тривоги підуть із негативною енергією. До того ж груша – символ родючості та ситого життя. Це, звісно, ​​невипадково - слов'янські племена навчилися заготовляти плоди дерева. Сушені, в'ялені, копчені на багаттях груші були запорукою ситого життя, дозволяли людям пережити зимову холоднечу, забезпечуючи організм важливими цілющими елементами. Найплодючіша груша в окрузі зводилася на символ родючості. Їй присвячували ритуали, якими закликали на допомогу духів природи допомогти тій жінці, яка могла народити потомство. Якщо таке дерево засихало чи вмирало, це служило зловісною прикметою загибелі всього племені. Чекали великої біди природного походження – неврожаю, голоду, морових хвороб чи рукотворного, наприклад – війни.\nГруша вважалася за священне дерево. Південні слов'яни іноді називали її деревом кохання. Груша вважається плодом мудрості та передбачливості. Якщо вам властиво приймати рішення необдумано, гаряча груша виявиться корисною. Вона сприяє мисленню та розумовому підходу до проблеми. Ця її якість високо цінувалася в давнину. Груша завжди вважалася плодом мудреців і філософів, крім того, плоди грушевого дерева були єдиною їжею мага перед чаклунським ритуалом - так він надавав собі сили думки і духу і захищав себе від можливого зіткнення з дияволом.\nГруші, з'їдені на заході сонця, допоможуть вам прийняти правильне рішення навіть у дуже складній ситуації.\nЗ грушевого дерева виходять чудові магічні жезли.\n\n Священне Каміння.\n\nДля Чертога Вепра у слов'янській традиції підходять каміння, що посилює рішучість, стійкість і духовний розвиток. До основних мінералів відносяться аметист, берил, опал, сапфір та лазурит. Ці камені допомагають впоратися з упертістю, спрямовуючи енергію на творення та мудре досягнення цілей.", "16.virgo": " Чертог Діви.\n\nЦе єдиний Чертог, названий не на честь звіра чи птаха, а присвячений образу людини, її духу (джива - санскрит). Але це не випадково, адже людина є частиною природи і має своє місце у програмі всесвіту. Без людини Яв (земний, світ людей) не мала б сенсу, вона вершина божого задуму. Чертог Діви - знак людей, які прийшли на землю творити. Їхнє найвище призначення зводиться до того, що після них на землі в Яві повинні залишатися плоди праці, думки, матеріальні блага. Тому небеса дарували покровителям цього чертога ті сутності, які дають силу та натхнення у розвиток та множення.\nДжива своєю божественною силою множить міць духу, а дерево яблуня як натхненник надає устремлінням людини матеріальної орієнтації. Тому серед Дів високий відсоток дуже організованих, логічно мислячих представників, котрі всіма силами націлені будувати та творити. Люди, які народилися в цьому Чертозі, дуже цілеспрямовані. Вони прагнуть пізнавати світ, виявляють лідерські якості та впертість. Ці люди мають всі якості лідера, здатні досягати наміченого, вони незалежні і самодостатні, здатні передбачати майбутні зміни. Негативно реагують, коли хтось намагається нав'язати їм свою думку щодо ухвалення важливих рішень. За надмірної зацикленості на власній особистості у людей чертога Діви може виявлятися сильна впертість.\nПід покровительством Живи народжуються дуже цілеспрямовані та активні люди. Вони з дитинства сповнені ідей та бажання здобувати знання та втілювати їх на практиці. Хороші стратеги, які чітко планують шлях до мрії і часто отримують намічене. Незважаючи на те, що серед них народжується дуже багато людей з творчим початком і баченням прекрасного, все ж таки небеса наділили їх надмірним бажанням досягати успіхів у матеріальному примноженні. Тому у виборі професії Діви часто жертвують своїми творчими устремліннями, обираючи життєвий шлях матеріального творення.\nСлід зазначити у характері Дів ґрунтовну частку запальності, якщо хтось із оточуючих чи партнерів у справі поставився до виконання планів абияк.\nДівам-холерикам властиво дуже швидко виходити за межі спокою, коли його підводять. Такою поведінкою вона змушує інших струснутись та мобілізуватися в роботі. Також слід зазначити наявність у Дів величезного потенціалу передбачення. Багато хто схильний пов'язувати таку здатність з якимись магічними властивостями, але насправді розум Діви настільки досконалий, що дуже швидко обробляє отримані факти та аналізує, отримуючи готовий прорахунок ситуації на багато кроків уперед.\nУ давнину розумні та інтелектуальні Діви не затримувалися в становищі простого землероба чи воїна, їм обов'язково вдавалося досягти становища волхва, голови племені чи воєначальника. Такі особи не працюють у полі, Діви народжені домагатися чільної ролі.\nОдружуватися Діва не поспішає, до будь-яких романтичних відносин підходить надсер'їзно. Створюючи сім'ю, Діва передусім подбає про будинок і стан, щоб створити найкращі умови для цього. Дружина теж намагається вибрати із тих, з ким можна будувати благополучний будинок.\nПотрібно обов'язково відзначити, що людина, що народилася в Чертозі Діви, є одним з тих, хто рухає розвиток людства вперед. Так само, як і Джива своїм живим священним потоком вдихає в Яв здатність до життя, так і Діва заражає своїм ентузіазмом та активними діями суспільство до вдосконалення та прогресу.\nЧоловіків, що народилися в Чертозі Діви, відрізняє м'який характер, добродушність та дружелюбність. Вони вважають за краще не вступати в конфліктні ситуації, проте це не означає, що вони терпітимуть приниження або випади на свою адресу. Якщо в цьому виникне потреба, чоловік Чертога Діви дасть потужну відсіч будь-кому, хто ризикне посягнути на його особистий простір, честь, гідність або спробує нашкодити його сім'ї та близьким. Маючи внутрішню творчу енергію, чоловік чертога Діви зазвичай реалізує її у художній чи музичній творчості, стає поетом, науковим діячем чи філософом. Завдяки прагненню недосяжних висот може стати першокласним керівником та беззаперечним лідером, якому під силу вміло організувати роботу своїх підлеглих. Жінки, що народилися в Чертозі Діви, як правило, ніколи не відчувають труднощів із зачаттям і складнощами під час вагітності та пологів, оскільки Богиня Жива піклується про вагітні та породіллі, допомагаючи їм легко виконувати свою природну функцію.\nЖінки, народжені в Чертозі Діви знаходяться під заступництвом богині Дживи - уособлення самого життя, вічної молодості та душевної чистоти. Жінкам чертога Діви вдається створювати міцні сім'ї, де завжди панує тепла і затишна атмосфера, гармонія, порозуміння і повага одна до одної. Жінка-Діва має дивовижну здатність передчувати події. Вона живе в ритмі зі світом і часто здається оточуючим «не від цього світу» через свою проникливість. Вона бачить приховану суть речей. Їй не треба пояснювати мотиви вчинків – вона відчуває їх на рівні душі. Часто має здібності до ясновидіння або цілительства. У них «жадібний» розум. Вони постійно навчаються, досліджують і накопичують знання, стаючи до зрілості справжніми джерелами мудрості. Незважаючи на зовнішню м'якість, Діва має величезну внутрішню силу. Вона не зазнає тиску і завжди йде своїм шляхом, прислухаючись до внутрішнього голосу. Для неї фізичний потяг вдруге. Їй потрібен чоловік, з яким вона зможе говорити про вічне, хто зрозуміє її багатий внутрішній світ. Навіть у шлюбі Діва залишається трохи загадковою та відокремленою. Їй необхідний особистий простір для роздумів та духовних практик.\n\n Бог Покровитель.\n\nБогиня Джива Діва Жива, Діва, Сива - Богиня Вічного Всесвітнього Життя, Богиня молодих та чистих Душ Людських. Богиня Джива дає кожній людині при народженні у Світі Яві чисту та світлу Душу. Богиня ДЖИВА є уособленням плодоносної сили Життя, вічної молодості, юності та закоханості, а також найвищої краси всієї природи та людини. Богиня-Покровителька чертога Діви у Сварожому Колі.\n\n Священне Дерево.\n\nЯблуня – дерево, що дає плоди знання. Це дерево – символ родючості, краси та багатства. З яблунею пов'язують матеріальний аспект. У неї завдання – надихати підопічного на досягнення результатів своєї праці. З деревини яблуні прийнято було робити амулети на багатство та множення благ у засіках. Від того, який урожай буде зібраний у полі, наскільки повними стануть засіки, залежить життєздатність сім'ї та всього роду. Говорять, що в Ірії на яблуні молодильні яблука ростуть. І той, хто їх їсть, ніколи не старіє.\nЯблуко - символ краси та досконалості, достатку та божественного дару, а також молодості, родючості та пізнання. Яблучна квітка – символ оновлення та розквіту, а також – прагнення до пізнання.\nЯблуко використовувалося в магії для залучення кохання. Квіти яблуні додаються в мішечки, вариво та ароматичне куріння, їх кладуть у розплавлений рожевий віск, відціджують та роблять свічки, які запалюють для залучення кохання. Найпростіший засіб – розрізати навпіл яблуко та запропонувати половинку тому, кого ви любите. Це забезпечить вам обом щастя.\nПротягом багатьох століть у Європі серед незаміжніх жінок були поширені гадання про кохання, в яких використовувалися яблука. Просто розріжте яблуко навпіл і порахуйте кількість насіння. Якщо кількість парна, то ви незабаром вийдете заміж. Якщо одне з насіння виявляється розрізаним, це означає, що ваші стосунки можуть бути дуже бурхливими. Якщо виявиться, що розрізано два насіння, то вам доведеться вдівство. Якщо кількість насіння виявиться непарною, то найближчим часом жінка заміж не вийде.\nЗ деревини яблуні виходять чудові чарівні палички, що особливо підходять для емоційних видів магії, а також любовних ритуалів. Яблучним сидром можна замінювати кров, коли це потрібно у старих рецептах.\nІз деревини яблуні можна вирізати фігурки. Це дерево жіночої сили, жіночої сексуальності, що пробуджує в жінці чуттєву сторону натури. Якщо ви хочете випробувати приплив еротичних сил, то лягайте спати влітку під яблунею, правда, вона охочіше ділиться своїми силами з молодими дівчатами. Під впливом енергії яблуні дівчина може уявити образ ідеального чоловіка, що відповідає їй, а уві сні побачити нареченого. Для енергії яблуні немає моральних правил, вона керується лише закликом природи.\n\n Священне Каміння.\n\nКамені для чертога Діви спрямовані на гармонізацію їхньої практичної натури, допомагаючи розвивати інтуїцію та зберігати баланс. Кращими каменями вважаються смарагд, сапфір, яшма, сердолік, нефрит та хризоліт. Ці мінерали захищають від негативу та підтримують здоров'я.", "4.snake": " Чертог Змія.\n\nНародження в Чертозі Змія передбачає людині світлу, яскраву долю. Представники чертога Змія відрізняються неймовірною активністю, яка спрямовується виключно на добрі справи. Рідко коли побачиш людей-змій, які сидять на одному місці і довго розмірковують про високі матерії. Вони перебувають у постійному русі, який залежно від ситуації та життєвих обставин може бути хаотичним чи впорядкованим. Відмінна риса людей цього періоду – мудрість. Однак у деяких ситуаціях вони схильні виявляти егоїзм та консервативність. Змії, що народилися в Чертозі, дуже комунікабельні, можуть досягти хороших результатів в інформаційній сфері. Також досягають успіху та поваги у сфері знань завдяки вмінню знайти в собі мудрість сил вогню.\nПредставники чертога Змія в коханні зазвичай розбираються краще за інших. Вони трепетно ​​вихваляють високе почуття, що виявляється в їхньому ніжному та дбайливому ставленні до свого обранця. У кохання вони готові поринути в голову, але вимагають такої самовіддачі від партнера. Якщо Змії помітять, що кохана людина не готова до будь-яких жертв задля збереження сімейної ідилії або відмовляється брати безпосередню участь у вирішенні нагальних проблем, такі стосунки довго не протримаються. Зміям потрібний не просто добрий коханець для задоволення тілесних втіх, а справжній друг і товариш, на якого можна покластися у скрутну хвилину.\nЧоловіки, які народилися в Чертозі Змія, завжди здатні мудро, виважено і тверезо оцінювати ситуацію, завдяки чому приймають правильні рішення, що дозволяють їм досягти успіхів у роботі та особистому житті. Чоловіків чертого Змія відрізняють вольовий характер і рішучість, тому вони завжди йдуть тільки вперед. Вони вміють слухати та здатні відмовитися від свого, іноді необ'єктивного погляду. Однак якщо докази їх не задовольняють, вони дратуються і перестають сприймати аргументи. Тому у спілкуванні з чоловіками чертога Змія дуже важливо зацікавити їх першою пропозицією – тоді компроміс можливий. Така властивість характеру може сприяти розвитку у чоловіків цього чертого егоїзму та самозакоханості. Жінки, що народилися в Чертозі Змія, вловлюють найменші зміни в емоційному стані людей, що знаходяться поруч із ними. Вони вміють любити по-справжньому, усім серцем та всією душею. Але їхній мінус полягає в тому, що вони і від інших вимагають того ж - повної та абсолютної самовіддачі. Жінки чертога Змія вміють звернути на себе увагу не лише своїми зовнішніми даними, а й уродженим умінням залучити будь-яку людину до відвертої розмови. Народження в Чертозі Змія передбачає людині світлу, яскраву долю.\n\n Бог Покровитель.\n\nБог Семаргл. (Вогнебог) Вишній Бог, охоронець Вічного живого Вогню та охоронець точного дотримання всіх Вогняних Обрядів та Вогняних Очищень. Семаргл приймає Вогняні Дари, Вимоги та безкровні Жертвопринесення на давніх Слов'янських та Арійських святах особливо на Красногор, у День Бога Купала та в дні Перуна, будучи посередником між людьми та всіма Небесними Богами. Вогнебог Семаргл - це вогняний пес з орлиними крилами.\n\n Священне Дерево.\n\nСвященним деревом чертога Змія вважається Липа. У слов'янській культурі це дерево асоціюється із сімейним щастям та природною красою. У народі вважалося, що якщо постояти деякий час під розлогою кроною Липи, то людині могли з'явитися різні надприродні можливості. Липа могла втішити у скрутну хвилину і дарувала натхнення перед новими починаннями. З Липи створювали домашнє начиння та робили обереги. Суцвіття липи (липовий колір) застосовують у медицині як потогінний засіб, а також для ароматизації чаю. Липа є цінним медоносом. У Європі липа використовується дуже широко завдяки її захисній силі. З цією метою гілки липи вішають над дверима або садять у сад. Якщо постійно носити із собою кору липи, це оберігає від отруєння, а листя та квіти застосовують у любовній магії. Оскільки це дерево символ безсмертя, його листя використовується в магії такого роду. Липу та лаванду в рівних частинах змішують та набивають суміш подушки. Ті, хто страждає на безсоння, можуть забути про цю проблему, якщо будуть спати на такій подушці. З дерева липи вирізають амулети на щастя і носять їх із собою. Мішечки з липовим кольором посилюють творчі здібності, особливо у дітей. Енергія її сильна та м'яка. Викликає почуття тепла та спокою. Сприяє рятуванню від депресії.\n\nМайже повсюдно вважалося, що в липу не б'є блискавка, тому липи, що ростуть біля церков, служили своєрідними громовідводами. Пояснювали це тим, що липа колись нібито попросила Бога, щоб він спрямовував блискавки в неї, а не в церкви, які будували поруч з нею; тому липу називали охоронницею церков і людей, що в ній перебувають.\nЦя здатність Липи, а також інші корисні властивості (цілюща сила, медоносність, м'якість деревини і т. д.) розглядалися слов'янами як результат її благословення згори. Відомі легенди, у яких у відповідь на готовність липи служити громовідведенням для церкви Бог нагороджує липу всіма названими якостями, а також морозостійкістю, здатністю швидко відновлюватися після потрапляння в неї блискавки та багато іншого.\n\nМ'якість і податливість деревини липи була переосмислена в різних жанрах слов'янського фольклору, причому, на відміну від побутової практики, де ця властивість липи оцінювалася позитивно і виявилася широко затребуваною, у фольклорі епітет липи отримував значення 'недовговічний, слабкий, бідний'. Це значення помітно, наприклад, у російській ліриці, де «липовий будинок» - будинок бідняка-горюна: «Іван молодий, не хитай головою, Не хитай головою, мені не бути за тобою, У Івана горюна ні худоби, ні живота; Одна липова хата, решітчасті ворота», в прислів'ї, що іронізує над бідністю: «Багат став: замість лакових чобіт взув липові». Образ «заіндевелої липи» (у підблюдних піснях) став символом безшлюбності: «Варта липа на крутій горі, маківки з кореня вся заініла».\n\n Священне Каміння.\n\nКамені чертога Змія спрямовані на посилення інтуїції, захист та розвиток мудрості. Основними мінералами вважаються аметист, лазурит, обсидіан та нефрит. Також використовуються гематит, гранат, смарагд та бурштин, які допомагають справлятися з енергією вогняного знаку.", "13.horse": " Чертог Коня.\n\nчертог коня - дивовижний час, коли активізуються сили різних вимірювань. Пік розквіту природних сил та період літнього сонцестояння, коли сонце та солярні духи, що дають енергію життя, панують у Яві на повну силу. Чертог Коня – час природної сили та пік розквіту всіх стихій. Кінь - символ сили, швидкості, родючості, працьовитості. Він уособлює значення молодої та сильної енергії життя. Цей Чертог символізує значення чоловічої енергетики, вже не юнацької вдалі, а дорослої сили, коли настав час вибрати дружину собі і зробити потомство. Літо, коли всі чертоги святкують силу Сонця – час найбільшої родючості землі. Це час, коли боги Прави приходили на землю, щоб дарувати блага та виконання бажань людям. Люди, що народилися в цей період, мають вміння легко справлятися з різними неприємностями та ударами Долі. Часто з них виходять чудові керівники. Вони здатні легко поєднувати воєдино те, що іншим дається з великими труднощами. Їм подобається процес інтеграції в житті, науці та роботі. Вони люблять земний світ і насолоджуються життям. Але вони повинні бути обачними, щоб не налаштувати себе лише на земні ідеали, оминаючи духовні.\nРозвиваючись духовно, люди чертога Коня здатні поєднувати у собі прояв сил усіх стихій, пізнати суть Темряви та Світла. Подібно до свого покровителя Купалу, народжені в Чертозі Коня мають яскраво виражену романтичність. Це дуже емоційні люди, які тонко сприймають світ. Перебуваючи у постійному сумніві, вони критично ставляться до того, що відбувається навколо, за що іноді помилково сприймаються іншими.\nУ Чертозі Коня народжуються ті, хто з надлишком наділений творчим натхненням. Їх багатий, насичений образами світ часто стає запорукою успішної реалізації себе в галузі мистецтва – художники, актори, музиканти.\nКоні – добрі, чуйні, але водночас і дуже вразливі люди. Їх ображає неувага до їхньої персони, адже вони найчастіше намагаються допомогти кожному нужденному. Схильні переживати та страждати, якщо стикаються з хамством та різкістю. Адже самі вони за натурою досить м'які та поступливі. До того ж у цьому Чертозі народжуються ті, хто з дитинства виявляє прагнення до розширення своїх знань.\nСильні сторони Коня – ерудованість, уміння швидко аналізувати ситуацію, генерувати різні плани та успішно їх втілювати у життя. Єдине, що часом псує втілення мрії в реальність - неймовірна невпевненість і нерішучість.\nЧертог Коня - знак дуже працьовитих людей, які усвідомлюють залежність отримання матеріальних благ від старань у роботі. Але їх не можна назвати дуже меркантильними особами, швидше вони прагнуть видобувати рясні плоди від праці своєї, але з усією щедрістю і не шкодуючи, можуть розділити результат з ближнім. Їм не властиво жадібно накопичувати багатства, скоріше успіх - той маркер, який тішить їхнє самолюбство.\nНадзвичайно ласі на лестощі. Для Коня має значення - яке визнання і резонанс у суспільстві викликає його дія. Тому Коні часто стають жертвами підлабузників і брехунів, що неймовірно їх ранить.\nОсобливою вірністю Коні не відрізняються. Звичайно, не без винятків, але часто молодість їх сповнена всяких романтичних пригод та історій кохання. Самі вони стають причиною сліз та душевних страждань інших. Лише з роками, наситившись вільним життям, схильні пов'язувати себе узами шлюбу. Зате потім намагаються зберігати вірність подружжю та цінують сімейний затишок та теплоту.\nЧоловіки, що народилися в Чертозі Коня, добрі, позитивні, розумні, відрізняються незвичайною фізичною силою та гарячим темпераментом. Вони можуть роздратуватися навіть з незначного приводу, але швидко відходять. Вони дуже відповідальні, у будь-якому випадку виконуючи покладені на них зобов'язання, але питання завжди впирається в їхню особисту зацікавленість. Ці чоловіки ніколи не працюватимуть з-під палиці. Якщо вони беруться за те лише тому, що так треба, навряд чи така справа буде завершена. Жінки, що народилися в Чертозі Коня, здавалося б, можуть здатися романтичними особистостями, що витають у хмарах. Разом з тим вони талановиті, тонко відчувають навколишній світ і людей, що знаходяться поруч із ними. Вони люблять безмежно і віддано, але так само люто вміють і ненавидіти, хоча зовсім не мстиві і легко забувають образи. У більшості випадків жінки Коні воліють весь вільний час приділяти сім'ї та підростаючому поколінню. Але деякі з них ставлять перше місце кар'єру, і тоді вони можуть довго залишатися на самоті.\n\n Бог Покровитель.\n\nКупала - Бог, який дає людині можливість створити будь-які Застереження та проводити Обряди Очищення Тілес, Душі та Духа від різних хвороб і недуг. Бог, що наставляє на радісне та щасливе життя. Купала - веселий і прекрасний Бог, який одягається у легкі білі шати, прикрашені квітами.\n\n Священне Дерево.\n\nВ'яз – дерево священне. У його кроні пов'язують і все погане йому скидають. З в'язової деревини часто робили обереги для будинку, горезвісні «півники», які прикрашали дах для захисту від пожежі, ковзани – кінські голови, які мали відганяти злі сили від будинку та господарства. Словом, в'яз шанувався як дерево-захисник, дерево-воїн. У середньовіччі лицарі робили із в'яза списи не лише через фортецю деревини. Вважалося, що в'язові списи вселяють воїну відвагу і приносять удачу у битві.\nЦе дерево справжніх душевних якостей справжнього чоловіка. Саме таким людям в'яз допомагає не впадати у відчай у невдачах, допомагає з гідністю знести поразку. В'яз не симпатизує невдахам, він не терпить розгильдяйства, готовності махнути на все рукою. Тільки тому, хто готовий знову підніматися щоразу, незважаючи на труднощі, всоте починати все спочатку, в'яз дає сили. Іноді одного гарного контакту із в'язом людині може вистачити довгі роки.\nЯкщо ви знемагаєте у боротьбі, якщо вам не вистачає соломинки, щоб утримати рівновагу – саме міцна в'язова гілка з радістю дасть за себе вхопитись і допоможе вибратися до світла.\nУ магії в'яз привносить у закляття стійкість та опір.\nДбає також про сильних і особливо самотніх жінок. Через те, що останнім часом, та й не тільки, завжди були жінки, які несли більший тягар відповідальності за себе та сім'ю, ніж чоловіки. У цьому випадку воно може карати чоловіків, через яких жінка опиняється у такій складній життєвій ситуації. Однак дама має бути дійсно дуже крутою, щоб отримати його прихильність. У такому разі вона стає ще сильнішою. Спалюйте і використовуйте в мішечках-талісманах, щоб позбавити себе шкідливого втручання. В'язу під силу позбавити вас від пересудів і пліток.\n\n Священне Каміння.\n\nКамінням-талісманами для чертога Коня у слов'янській традиції вважаються бурштин, аметист, димчастий кварц та топаз. Вони приносять гармонію, силу та оберігають від негативу. Часто обереги виконуються з балтійського бурштину у сріблі.", "3.swan": " Чертог Лебедя.\n\nПредставникам цього чертога, як правило, властива унікальна душевна організація, але також їх відрізняє завидна працьовитість. Вони завжди розраховують тільки на себе і не покладаються на удачу. Крім того, вони мають здатність проникати в таємниці Долі як своєї, так і інших людей. Вони процвітають у землеробстві, вкладають усю душу у свою нелегку працю. Віддають перевагу традиційному життєвому укладу, розміреному і спокійному. Але не завжди вміють ухвалювати рішення. Звичайно, чого не відібрати - це мудрість і проникливий розум Лебедя. Від їх пильного і спостережливого погляду не зможе сховатися жодна дрібниця. Вони помічають усе, що відбувається, але завжди вимовляють вголос свої висновки. Чертог Лебедя наділяє людину прагненням влади, вмінням співпереживати і розуміти чуже горе. Вважається, що люди, народжені в Чертозі Лебедя, мають унікальний дар «дивитися в корінь» будь-якої ситуації.\nЛебеді мають відмінні організаторські здібності, їм важливо впорядковувати навколишнє середовище, робити його зручним і розумним. Їм подобається, щоб довкола все було красиво та доглянуто – цими якостями в характері керує Макошь. Від неї Лебедеві передалося почуття пізнання прекрасного, любов до творчості. Від богині Лебедя їм дісталася м'яка вдача і схильність до вірного кохання. Для Лебедя завжди важливий той, кому віддано їхнє серце. Їхній сенс - піклуватися про кохану людину і прагнути самопожертву заради неї.\nУ «Слові про похід Ігорів» є опис лебединої пісні, яку співала чи точніше голосила-плакала Ярославна в тузі за своїм чоловіком. Лебединою вірністю називають почуття, коли є схильність до повного розчинення в любові до свого партнера. Ось і люди цього чертога дуже боляче переживають будь-який розрив чи розлучення з коханим.\nКрім того, Лебеді ще дуже цінують свій будинок. Їхнє житло має священні кордони, які ревно охороняються від будь-якого вторгнення. Лебеді намагаються зробити житло затишним та спокійним місцем, щоб зі своєю родиною насолоджуватися благополуччям. Намагаються, щоб будинок був комфортним місцем для найближчих.\nЛебеді – досить неконфліктні люди, які намагаються обминати сварки та дискусії. Але якщо вже комусь спала на думку зворушити гордість Лебедя, то така людина негайно отримає відсіч. Лебеді з прекрасного птаха миттєво перетворюються на грізного супротивника. А оскільки вони досить розумні, то і відсіч буде дано хитро, з вигадкою так, щоб надалі не хотілося. Народжені в Чертозі Лебедя люди, чого в них не відібрати - це мудрість і проникливий розум Лебедя.\nЧоловіки-лебеді рідко впадають у паніку. Зовні вони можуть здаватися холодними або відстороненими, але це лише маска. Усередині них вирує робота думки. Вони вважають за краще спочатку оцінити ситуацію з усіх боків і лише потім діяти. Іноді можуть бути надмірно консервативними і вимагати від домочадців дотримання встановлених ними правил. Зв'язок із Макошу дає їм дар «бачити наскрізь». Чоловіка-Лебедя важко обдурити - він відчуває брехню на підсвідомому рівні. Часто вони мають філософський склад розуму і цікавляться таємними знаннями або психологією. Якщо довго відчувати їхнє терпіння, «тихий вир» перетворюється на шторм. Гнів Лебедя холодний та руйнівний. Іноді вони вважають свою думку єдино вірною і важко приймають чужу точку зору. Схильні до самокопання і можуть впадати в депресивні стани, якщо відчувають, що їхнє життя втратило «правильне» русло. Жінка, народжена в Чертозі Лебедя – це втілення спокійної сили, грації та глибокої житейської мудрості. Оскільки її покровителькою є Макош, характер такої жінки пронизаний творчою енергією. Вона – справжня хранителька вогнища. Вона має природний дар організовувати простір навколо себе так, щоб усім було тепло і затишно. Її будинок часто стає «повною чашею», де завжди пахне смачною їжею та панує порядок. Часто має талант до творчості - шиття, в'язання або дизайну, вкладаючи в це душу. Заради благополуччя близьких вона готова відсунути свої інтереси на другий план, але вимагає за це щирої подяки та поваги. Вона ніколи не дозволить принижувати себе. У її характері є шляхетна гордість, яка не дозволяє їй опускатися до дріб'язкових склок. Якщо її межі порушені чи зачеплені інтереси її дітей, «тихий Лебідь» перетворюється на грізну захисницю. Її гнів може бути раптовим та дуже сильним. Як і чоловіки цього знаку, жінки мають потужне «шосте почуття». Вони часто бачать пророчі сни або просто заздалегідь знають, чим закінчиться та чи інша справа. Обдурити таку жінку практично неможливо – вона відчуває фальш на рівні інстинктів. Для жінки-Лебедя життєво важливо знайти баланс між турботою про інших та увагою до себе. Якщо вона забуває про свої бажання заради сім'ї, її енергія виснажується, що веде до нападів дратівливості.\n\n Бог Покровитель.\n\nБогородиця Макошь. Богородиця Макошь - Небесна (Сва) Богородиця, Справедлива Богиня щасливого жереба та Долі. Разом зі своїми дочками, Долею та Недолею, визначає Долі Небесних Богів, а також долі всіх людей і всіх нащадків Роду Небесного, які живуть на нашій Землі, плетячи для кожного з них Нитки Долі. Тому багато хто звертався до Богини Макоші, щоб вона довірила сплітати Нитку Долі в клубок молодшої дочки - Богині Долі. Богиня Макошь у всі часи була дуже уважною та дбайливою Покровителькою ткацтва та всілякого рукоділля, а також стежила за тим, щоб на полях, де орачі (селяни) вкладають Душу у свою нелегку працю, зростав гарний урожай.\n\n Священне Дерево.\n\nТе дерево, яке живить своїми соками життя підопічного, називається сосна. Це дерево милосердя та доброти. Його силою можна було виганяти бісів будь-якої хвороби, тому воно широко застосовувалося для амулетів, пов'язаних зі здоров'ям. Сосна наділяла величезною мудрістю та милосердям своїх підопічних. Лебедя, що народилися в Чертозі, отримували від сосни можливість зняти втому, відновити свої сили. Однією з корисних властивостей сосни вважається її можливість лікувати серцеві захворювання та проблеми дихання.\nСпалюйте подрібнені та сухі голки хвої, щоб очистити будинок взимку від злих сил. Особливо рекомендується змішувати в рівних частках з ялівцем та кедром.\nСоснові шишки носять із собою, щоб підвищити здатність до народження дітей та зберегти силу в старості, горіхи їдять із тією ж метою.\nСосна - дерево спокою та висоти духу. Якщо у вашому житті прийшов важливий момент, вирішується ваша доля і необхідно у спокійній обстановці відповісти на низку серйозних питань, без спілкування з сосною не обійтися. При прямому контакті сила сосни відчуває роздратування та досаду, які щодня накопичуються у вашій душі. Енергія сосни допоможе вам позбутися нервових розладів, стресу. Жоден невроз не встоїть під впливом. Сосна – милосердне дерево. До нього слід звертатися із відкритою душею. Сосна здатна очистити ауру людини від сторонньої дії, частково зняти псування. За старих часів вважалося, що запах сосни сприяє звільненню від почуття провини.\n\n Священне Каміння.\n\nКамені чертога Лебедя, покровителем якого є богиня Макошь, покликані гармонізувати емоційну стійкість, зміцнювати інтелект та захищати. До основних магічних каменів для народжених у період відносяться обсидіан, нефрит, лазурит (ляпис) і халцедон.", "11.elk": " Чертог Лося.\n\nЧертог Лося невипадково отримав у покровителі богиню Ладу - праматір більшості слов'янських богів і велику захисницю всіх слов'янських племен і родів. Весняне сонце вже повністю увійшло у свою силу, природа розквітла і відродилася у всій красі – той час, коли панують обидві берегині – Лада та Мати-лосиха. Чертог Лося отримав свою назву на честь лісового духу, великої та всесильної власниці звірів Матері-лосихи.\nБудучи символом лісового світу, він може бути привітним для доброї людини або жорстоко покарати того, хто прийшов із поганими намірами. Але якщо людина прийшла вбивати в ліс заради забави, то мати-лосиха може спричинити покарання, заплутавши-закрутивши в лісі, вбивши беззахисного на розтерзання хижим звірам.\nВажливою особливістю, що відрізняє Свароже коло від своїх пізніших аналогів-гороскопів, є божественна сила, яка дає допомогу кожному знаку. Чертог Лося знаходиться під заступництвом богині-богородиці Лади, а поживну силу тим, хто народився в цей час, дає береза. Люди, народжені в цьому Чертозі, відрізняються неймовірною витривалістю, товариськістю і велелюбністю. Однак їм буває складно довіритися незнайомій людині, вони не вірять нікому і нічого не беруть на слово. При цьому вони цінують прекрасне, щосили прагнуть осягнути мистецтво краси і мистецтво любові. Їхні серця завжди наповнені чуттєвістю, ніжністю та романтикою. Вони можуть допомогти іншим знайти вірний шлях до кохання, налагодити стосунки між рідними та близькими.\nЛюди чертога Лося дуже цінують вміння поважати іншу людину. Це час, коли на землю приходять добрі та добрі люди. Знак Лося приносить у характер такі якості, як працьовитість, доброту, спокій, завзятість.\nЛосі рідко бувають злопам'ятні, зазвичай вони вміють відпускати. Будучи досить прямолінійними, не тримають у собі емоції – прямо говорять про те, що думають.\nЛосі - активні екстраверти, їм властиво заповнити собою весь простір. Така людина обов'язково ділиться своїми емоціями, переживаннями, спостереженнями та висновками з усім світом. Визнання та увага оточуючих йому необхідне як повітря. Якщо трапляється вимушене пустельництво, то Лось почуватиметься зовсім нещасним. Тільки перебуваючи у бурхливому потоці подій, він живе та активно підживлює свою енергетику.\nНе можна назвати цих людей усидливими інтелектуалами, скоріше це знак людей-трудівників, творців, всіх, хто прийшов на землю, залишити після себе відчутні багатства.\nЦим людям не властиво брехати. Вони не вміють брехати і внутрішньо не готові до будь-якого прояву брехні. Лось дещо наївно всіх людей міряє власною міркою, але світ не такий добрий, тому він, зіткнувшись із заздрістю, брехнею чи підлістю, занепадає духом. Реакція Лося не змушує довго чекати – поганих людей виносить за межі свого спілкування без надії відновлення стосунків. Часом така категоричність стає причиною розлучень та сварок у сім'ї.\nЛось – відповідальний сім'янин, де на першому місці для нього знаходиться щастя та благополуччя домочадців, багатство та ситість близьких.\nЧоловіки, що народилися в Чертозі Лося, прямолінійні абсолютно в усьому, навіть тоді, коли йдеться про романтичні стосунки. Їм властиво переконувати оточуючих у своїй правоті і вони дуже комунікабельні. Їх розвинений розум дозволяє їм легко впливати на оточуючих за допомогою слів, вони можуть стати прекрасними ораторами, керівниками, лідерами. Однак таке трапляється нечасто, оскільки чоловіки чертога Лося схильні до безтурботного життя, їх обтяжують будь-які правила та умовності. До вибору супутниці життя вони ставляться дуже відповідально, і зазвичай не поспішають першими робити крок до зближення.\nЖінки, що народилися в Чертозі Лося, можуть багато часу провести в пошуках супутника життя, оскільки постійно розчаровуються в людях, знову відкривають у собі віру в них. Вони рідко вірять комусь на слово, і той, кого вони погано знають, ніколи не зможе стати для них авторитетом. Іноді жінки Чертога Лося бувають схильні до нервових розладів, оскільки часто й багато переживають з приводу роботи, здоров'я рідних, успіхів своїх дітей. У той же час, жінки чертога Лося прагнуть самі виконувати свої обов'язки, оскільки вважають, що якщо людина хоче, щоб робота була виконана добре, вона має зробити її сама.\n\n Бог Покровитель.\n\nЧертог Лося невипадково отримав у покровителі богиню Ладу - праматір більшості слов'янських богів і велику захисницю всіх слов'янських племен і родів. Весняне сонце вже повністю увійшло у свою силу, природа розквітла і відродилася у всій красі – той час, коли панують обидві берегині – Лада та Мати-лосиха.\n\n Священне Дерево.\n\nБереза ​​– важливе дерево в енергетиці слов'янського народу. Йому надають право зберігати цілющу енергію, що живить будь-якого Русича. Неймовірна краса цього дерева стала натхненням для створення безлічі легенд, пройнятих любов'ю до берези. Опис берези, мабуть, найліричніше з усього ряду тотемних символів. Їй приписують заступництво здоров'ю всякого, у чиїх жилах тече слов'янська енергетика. Вона є символом любові, краси і молодості.\nБереза ​​вважалася найсильнішою рослиною для позбавлення від недуг. Навіть лазневий березовий віник – невипадковий предмет. Обряд омивання в лазні із застосуванням березових гілок не що інше, як лікарський обряд, покликаний повернути силу духу в тіло та життєву енергію будь-кому.\nКрім цього, береза ​​допомагала у рятуванні від хвороб дітям. У тіні її листя залишали дитину грати, щоб матінка-береза ​​забрала її недугу.\nНа свято Лади було прийнято прив'язувати до гілок дерева різнокольорові стрічки. Примовляючи подумки бажання, дівчата та жінки просили у берези виконання своєї мрії.\nТакож існує обряд, що описує викидання зла зі свого будинку віником із березових прутів. Досі зберігся звичай – на Трійцю викидати зло з дому березовими гілками. Це давній звичай слов'ян, що дійшов до нас, допомагає позбутися від чаклунського сміття у своєму житлі.\nРівним, м'яким, спокійним, але водночас повноцінним потоком ллється енергія берези, але з усіма ділиться енергетикою наша красуня. Потоками сили вона обдаровує лише тих, чия душа відкрита для Світла.\nКажуть, що береза ​​біля будинку відганяє від його мешканців кошмарні сни. Батьки наші називали білоствольну красуню - деревом Життя і наділяли її магічними та цілительськими силами і вірили в її божественне походження.\nІснує повір'я, що у першій половині травня береза ​​має найбільшу лікувальну силу. У цей час можна зібрати її сік і напувати невиліковних і слабких людей, щоб ті швидше вилікувалися та відновили сили. У кожного дерева обов'язково просили дозвіл та з одного брали близько літра соку. Потім дякували і перепрошували, обробляли рану смолою. Дерево донора більше не чіпали до наступного року та гілки з нього не обрізали.\nНа бересті пишуть чорнилом із дубових горішків та пером із крила ворона рунічні заклинання. Також захищає будинок та домочадців від удару блискавок. З березового дерева робили люльки для новонароджених.\n\n Священне Каміння.\n\nКращими натуральними каменями-талісманами вважаються агат, смарагд і нефрит, які допомагають розкрити енергію, властиву цьому знаку.", "5.crow": " Чертог Ворона.\n\nЧас Ворона - це період зимового сонцестояння, коли зима сковує всі земні чертоги, природа завмирає і готується битва за відродження Яви. Для слов'ян, як і інших древніх народів, ці дні мали сакральне значення - переможе Світло чи Темрява, чи почне додаватися сонячний день. Чертог Ворона названо на честь речей птаха, символу мудрості та зберігача таємниць. Саме ці якості найбільше простежуються в людях, народжених під час Ворона – вони мудрі, спокійні та цілеспрямовані. Ще час Ворона перебуває під владою бога Коляди. Для слов'ян цей час очікування - чи переможе світло, чи почне додаватися день, чи зменшиться зимова пітьма, чи відродження Весни. Чертог Ворона - час великої битви Темряви та Світла за владу в Яві. Це час, коли бог Коляда перевертає коло, яким йде Сонце. Ім'я Коляди має походження від слова коло. Тобто формально Коляда той, хто веде Сонце по колу, змінює день і ніч, зиму та літо.\nЛюди, що народилися в цьому Чертозі, неординарні, добрі та приємні у спілкуванні. Найчастіше вони можуть налагодити своє сімейне життя до 40 років. Ці люди часто дуже активні та енергійні, але для відчуття гармонії поруч із ними має бути супутник життя. Прагнучи знайти любов на все життя, люди чертога Ворона в цьому пошуку можуть бути дуже закоханими і часто міняти партнерів. Чертог Ворона вносить у характер своїх підопічних величезну частину мудрості та спокою. Це ті люди, які стають духовними наставниками та ватажками слов'ян. У тому характері найрозвиненіші риси - завзятість, розважливість, прагнення знанням. Все, що обов'язково дає нам корисні зміни. У багатьох цивілізаціях описано народження синів божих у людській подобі під час зимового сонцестояння. У Воронов чудово розвинений дар переконання та красномовства. Їм дана влада над душами та серцями людей, що сприяє розвитку можливості сходження Воронов у ранг авторитетів, духовних наставників чи проповідників. Рідко той, хто народився під час Ворона залишиться на нижчому ступені розвитку особистості - це зовсім нехарактерно для них.\nУ Воронах зібрано величезний запас життєвої енергії, вони активні, рішучі, діяльні. З раннього дитинства розуміють, що праця – запорука їхнього успіху. У цьому слід зазначити, що Ворон дуже матеріально націлений. Більшість їх устремлінь спрямовано поліпшення власного добробуту, що нерозривно пов'язані з благом всього людства. Для Воронов важливо зберегти і примножити своє становище у суспільстві.\nЇм важливо віддавати, ділитися своїми емоціями та плодами життєдіяльності. Навіть свої плани вони нецілеспрямовано проектують на все людство, для них це фактор, що визначає виконання їхньої місії – творити добро для всіх, бути необхідною ланкою в людському роді. Величезним лихом може обернутися їх психіки вимушене самотництво. Нестача спілкування, обміну енергетичними потоками з іншими живими істотами здатна занапастити Ворона.\nВажливою рисою у Воронов слід зазначити неприйняття брехні. Цим людям не властиво брехати самим, а тим більше вони нещадно викривають брехунів, як головних руйнівників добра. Бо будь-яка брехня несе в собі зерно Зла, яке завжди дає негативні сходи. В опис характеристики Ворона обов'язково потрібно додати такі якості, як принциповість, доброта, миролюбність, терпіння. Їхній розум має величезний потенціал до розвитку, пізнання наук. Загалом, вони можуть бути добрим прикладом для наслідування, тому що головними рисами у Ворона завжди стають ті, що спрямовані на позитив і творіння.\nЧоловіки, що народилися в Чертозі Ворона, дуже активні, життєрадісні та діяльні. Вони постійно прагнуть щось робити, чогось прагнути, у них завжди багато різних планів. Однак, незважаючи на свій активний і часом безшабашний спосіб життя, в побуті вони вкрай скрупульозні, віддають перевагу спокою та затишку. Особливо це починає проявлятися із віком. Чоловіки чертога Ворона часто стають вчителями та наставниками, оскільки їм подобається передавати накопичені знання та досвід іншим поколінням. Жінки, що народилися в Чертозі Ворона, часто з дитинства демонструють неординарні і навіть екстрасенсорні здібності. Часто вони кидаються у вир почуттів з головою, що нерідко призводить до сумних результатів. Жінки чертога Ворона часто бувають уразливими, оскільки їхня тонка і вразлива натура дуже чутлива навіть до нешкідливих жартів. У вихованні потомства вони проявляють себе з кращого боку, будучи для дитини люблячою і дбайливою матір'ю, близьким другом та мудрим порадником в одній особі. Чертог Ворона вносить у характер своїх підопічних величезну частину мудрості та спокою.\n\n Бог Покровитель.\n\nБог Коляда. У давнину Вишній Бог Коляда дарував багатьом родам, що переселилися в західні землі, систему обчислення сезонного часу для ведення польових робіт - Календар (Коляди дар), а також свої Мудрі Веди, заповіді та настанови. Коляда є Богом-Покровителем ратних людей та Жреців. Коляду часто зображували з мечем у руці, причому клинок меча був звернений вістрям донизу. Меч, звернений вістрям вниз, в давнину означав збереження Мудрості Богів і Предків, а також безперечне дотримання Небесних Законів, як це встановлено Богом Сварогом для всіх чертогів Сварожого Кола.\n\n Священне Дерево.\n\nМодрина - дерево просвітлення та священного заспокоєння. Воно дарує своїм підопічним найвищі знання таємниці миротворства. Дерево мудрості та розуму здатне наділити величезними знаннями та душевним спокоєм. Люди, народжені під заступництвом модрини, приходять у світ Яві мудрецями вже виходячи з материнського лона. На них сходить таємниця просвітництва, вони ті, хто здатний внести в наш світ волю вершників. Модрина - заспокійливе дерево, що володіє м'якою та світлою енергетикою. Якщо людину щось лякає, її мучать сумніви і безпричинне занепокоєння, спілкування з модриною принесе йому велике полегшення. Вона зцілює важкі нервові розлади, що особливо супроводжуються нападами меланхолії, та депресію. Її вплив допомагає побачити життя з найкращого боку. Чи допоможе вона якщо вам не вистачає впевненості в собі, ви боїтеся провалів або вважаєте, що ви не такі гарні, як оточуючі. Допоможе досягати мети будь-яким способом та брати від життя набагато більше. Модрина носять із собою або на тілі, щоб захистити себе від чаклунства і захистити від поганого ока.\n\n Священне Каміння.\n\nКамінням-талісманами для чертога Ворона вважаються агат (особливо чорний) та вулканіт. Ці мінерали символізують мудрість, стабільність та зв'язок із природою, допомагаючи розкрити потенціал людей, народжених під заступництвом бога Коляди. Також часто використовується раухтопаз як камінь близький до цього знаку.", "9.fox": " Чертог Лиса (Лисиці).\n\nЧертог Лиса панує в той час, коли весна вступає у свої права – це час загибелі демона Зими та відродження, пробудження духу Весни. У момент весняного рівнодення відбувається чаклунство - відступає Темрява, даючи можливість світлому дню стати довшим. Чертог Лиси отримав назву на честь символу хитрості, розуму, краси та перетворення. Вважалося, що лисиця своїми хитрими хитрощами допомагає духу Весни увійти в права і зміцніти, перемігши сутінки зимового часу.\nЛисиця у слов'янській міфології - персонаж, одягнений неймовірним розумом, здатністю перетворення, хитрістю.\nУ цьому в нього немає чіткого розмежування на позитивне чи негативне значення героя. Лисицю поважали, при цьому побоювалися стати жертвою її прокази. Чертог Лиси приносить в характер людини унікальну властивість пластичності. Лисиці можуть досягати різного становища в суспільстві, потрапляти в будь-які ситуації, але що не забрати - завжди викрутяться, вивернуть все собі на користь. Ця людина неймовірно розумна, прозорлива, цілеспрямована. Ті, хто народився в цьому Чертозі, вміють перевтілюватися, змінюватися відповідно до моменту, що диктує обставини. Вони не позбавлені духу авантюризму, але будучи персонами, орієнтованими на отримання вигоди, все ж таки дуже обережно підходять до реалізації своєї мрії.\nЇм властиво будь-який свій крок продумувати і прораховувати з урахуванням - чи піде на користь, чи завдасть втрат задумане. Людина цього чертога має добре розвинене почуття міри. Він скрупульозно ставиться до своїх витрат, вміє вдало вкласти капітал, щоб отримати прибуток.\nЯк правило, Лиса навіть не здобувши хорошої освіти, вміє досягти високого становища в суспільстві. Опис Лисиця не може обійтися без згадки про його сильні якості характеру. Це ті люди, які ніколи не відмовляються від своїх поглядів. Вони мають неймовірну завзятість, завжди відстоюють власну думку.\nУ коханні та серцевих справах людина, народжена в Чертозі Лисиці, найчастіше схильна до вірності. Для нього невелике значення має зовнішня привабливість партнера, він швидше віддасть перевагу внутрішній красі обранця. Якщо доля подарувала їм спокійні, комфортні стосунки, Лисиця здатна пустити весь свій арсенал позитивних якостей, щоб сім'я була забезпечена і задоволена. Велике значення у житті Лис грають діти. Це ті створіння, які здатні полонити лисяче серце і вити з нього мотузки. Лисиці розчиняються в дітях без залишку, дозволяючи їм практично все і балуючи, найчастіше навіть на шкоду шибеникам. На їх захист та забезпечення всіх капризів у Лиси йде величезна кількість часу та фінансів.\nТак само варто згадати, що Лисиця обов'язково володіє хоча б мінімальними здібностями до магії та чаклунства. Часто вони помічають за собою здатність до ясновидіння, лікарських можливостей або талант до змови, зняття псування.\nЧоловіки, що народилися в Чертозі Лиса, мають стриманий і водночас рішучий характер, а також тверду непохитну волю, що дозволяє їм добиватися поставленої мети у короткий термін. Але часто вони дуже багато міркують, замість того, щоб нарешті почати щось робити. Чоловіки чертога Лисиці не приймають монотонну, одноманітну працю, яка просто «вбиває» їхній інтерес до життя. Їхнє справжнє покликання - приносити відчутну користь, тому найчастіше вони займають керівні посади. Чоловіки чертога Лисиці - це тонкі стратеги, інтелектуали та майстри дипломатії. Життя чоловіка-Лиса – це нескінченний пошук відповідей, прихованих смислів та найбільш ефективних шляхів до мети. Це не підлість, а саме життєва мудрість. Він знайде вихід із ситуації, яка здається тупиковою, використовуючи логіку та нестандартне мислення. Вони вміють подобатися. Маючи природний магнетизм, Лис легко втирається в довіру, майстерно використовуючи дар переконання. Вони рідко будують повітряні замки. Кожна їхня дія має приносити результат - матеріальний чи інтелектуальний. У коханні він воліє гру, завоювання та легкий флер загадковості. Йому важлива інтелектуальна близькість із жінкою. Лис зробить все, щоб його сім'я нічого не потребувала. Він вміє видобувати ресурси буквально «з повітря», забезпечуючи комфорт та стабільність. Навіть проживши з ним 20 років, дружина може не знати про його деякі плани чи думки. Він залишає за собою право на таємну кімнату в душі.\nЖінки, що народилися в Чертозі Лисиці, постійно стоять перед тим чи іншим вибором: моральним, матеріальним, філософським через надмірну цікавість - їм цікаво спробувати обидва варіанти. Вони не бувають задоволені ні синицею в руці, ні журавлем у небі – їм потрібне і те, й інше одночасно. Тому жінки чертога Лисиці іноді можуть бути досить егоїстичними. Щоб такого не сталося, поруч із ними завжди мають бути мудрі наставники: спочатку батьки, потім чоловік та вірні друзі. Жінка чертога Лисиці - це втілення жіночої хитрості в найблагороднішому значенні цього слова. Її покровителька, богиня Марена (Мара), наділяє її чарівною чарівністю, холодним розумом і здатністю виживати в будь-яких умовах. Жінка-Лис – це загадка, яку можна розгадувати все життя. Вона рідко буває прямолінійною, воліючи досягати цілей обхідними шляхами. Вона має неймовірний шарм. Навіть не будучи класичною красунею, вона притягує погляди завдяки внутрішньому вогню та впевненості. Їй треба знати все. Вона обожнює плітки, новини і нові знання не заради цікавості, а щоб володіти інформацією - головною зброєю Лисиці. Вона як вода - набуває форми будь-якої судини. Лис легко вписується у вище суспільство, у робочий колектив чи сувору похідне життя, скрізь почуваючи себе господаркою становища. Вона рідко вірить у слово. Кожне твердження вона перевіряє на логіку та вигоду.\nТака жінка - не просто супутниця, це майстерний маніпулятор (часто на благо), стратег та натхненниця.\nЛисиці воліють працювати у сфері, пов'язаній із захоплюючими подіями, пошуком інформації та творчою самореалізацією. А якщо робота цього не приносить, вони вносять у своє життя додаткові пригоди: поїздки, походи, подорожі. Люди чертога Лиса мають добре розвинене почуття міри.\n\n Бог Покровитель.\n\nМара (Марена, Морена) Велика Богиня Зими, Ночі та Вічного Сну та Вічного Життя. Богиня Марена, або Марена Свароговна, одна із трьох наречених сестер Багатомудрого Бога Перуна.\n\n Священне Дерево.\n\nСвященним деревом чертога Лиси за слов'янським календарем є граб. Цей оберег символізує стійкість, рішучість, допомагає долати фізичні та душевні рани, позбавляє зайвої квапливості та захищає від наговорів.\n\n Священне Каміння.\n\nКаміннями Чертога Лисиці є лавовий камінь і чорний агат.", "8.wolf": " Чертог Вовка.\n\nВовкам може бути властива жорсткість, але не жорстокість. Вовки обережні, але не агресивні. Інтроверти, завжди віддадуть перевагу своєму близькому колу або самоті - галасливим компаніям. Уникатимуть конфлікту, поки не станеться справжня загроза.\nНападати на Вовків – собі дорожче, з ними треба жити в мирі. Тоді вони будуть найкращими товаришами.\nВовкам властива рішучість, але вони завжди обережні і часто з презирством ставляться до людей без внутрішнього стрижня. Вони схильні ідеалізувати оточуючих людей, а тому часто розчаровуються у невірності та легковажності людей.\nВовкам властива вірність у стосунках. Чоловіки-вовки відважні, іноді нерозважливі, на перший погляд, але вони завжди знають, чого хочуть. Жінки-вовки рідко бувають старими дівами, переважно вони завжди з партнером.\nНароджені в Чертозі Вовка можуть працювати лікарями, поліцейськими, служити в армії, вони – добрі та чесні журналісти, які поважають факти.\nБог-покровитель Вовка - Велес, дає їм багато умінь у галузі землеробства, ведення домашнього господарства. Так ... знань та житейської мудрості. Будучи володарем землі та води, Велес постає унікальним провідником душ і вартовим меж між світами, чия здатність безперешкодно проникати в Наву та пов'язувати світ живих зі світом предків робить його єдиним божеством, що має доступ до всіх сфер світобудови. само з них виходять чудові мисливці та майстрові.\nЧоловіки, народжені в цьому Чертозі, - це особи з непростим, «диким» характером. Вони поєднують у собі відданість зграї та абсолютну потребу в особистій свободі. Вони не люблять поверховості. Якщо Вовк за щось береться, він докопається до витоків, чи то наукова проблема, чи будова двигуна. Навіть будучи душею компанії, такий чоловік часто почувається відокремлено. Йому життєво потрібен час, щоб «піти в лігво» і побути наодинці з думками. У конфліктних ситуаціях вони діють жорстко та стрімко. Вони не шукають бійки, але якщо на їхню територію чи сім'ю зробили замах - пощади не буде. Від них рідко почуєш порожні компліменти. Вони прямолінійні, часом до грубості, зате ви завжди знаєте їхню правдиву думку. З ним буває важко через його скритність. Він не з тих, хто обговорюватиме свої почуття за вечерею; його любов проявляється у справах, а не в словах. Якщо чоловік-Вовк – це воїн та захисник, то жінка цього знака – це хранителька смислів, інтуїтивний стратег та «сірий кардинал» своєї родини. Вона бачить людей наскрізь. Обдурити таку жінку практично неможливо – вона зчитує фальш на рівні інстинктів. Їй важливо розуміти, як улаштований світ. Це ті жінки, які в дитинстві розбирали іграшки, а у дорослому віці постійно навчаються, проходять курси чи вивчають психологію. Вона рідко скаржиться. Навіть у найважчі часи вона триматиме спину прямою, воліючи справлятися з проблемами самостійно. У неї дуже висока планка – як для себе, так і для оточуючих. Це часто робить її шлях на щастя непростим, оскільки вона не згодна «менше». Вона довго придивляється до партнера. Їй не потрібен просто супутник, їй потрібен соратник, рівний за силою духу. Навіть у найщасливішому шлюбі їй потрібен свій куточок, свій час та свої секрети. Спроба тотального контролю з боку чоловіка спричинить негайний розрив. Вона — сувора, але справедлива мати. Вона не балуватиме дітей надмірно, її мета - виховати їх сильними, самостійними та готовими до життя. Як і чоловіки цього чертогу, жінки-вовки схильні до глибокої прихильності. Зрада їм - єдина річ, яку неможливо пробачити.\n\n Бог Покровитель.\n\nВелес є одним із найшанованіших богів у слов'янському язичництві, він може вважатися богом родючості, сільського господарства, тваринництва, багатства, знань та житейської мудрості. Будучи володарем землі та води, Велес постає унікальним провідником душ і вартовим меж між світами, чия здатність безперешкодно проникати в Наву та пов'язувати світ живих зі світом предків робить його єдиним божеством, що має доступ до всіх сфер світобудови.\n\n Священне Дерево.\n\nСвященне дерево цього знаку - тополя, яка широко шанується людьми за здатність поглинати негатив з повітря. Тополя за своєю природою є «енергетичним вампіром» і поглинає негативну енергію не лише з довкілля, а й від людей. Якщо посадити дерево біля будинку, то господарі можуть відчути депресію. Пояснюється це просто - тополя здатна відібрати в людини життєву енергію. Щоб очистити будинок від негативної енергії чи зняти напружену атмосферу, давні слов'яни зазвичай використовували невеликі шматочки дерева, які розставляли у різних кутах різних кімнат.\n\n Священне Каміння.\n\nКамінням-талісманами для чертога Вовка традиційно вважаються аметист (гармонія), бірюза (захист), блакитний топаз, гранат, зелений агат, місячний камінь, хризоліт та цитрин. Ці мінерали підтримують безстрашність, мудрість та захист від пристріту." }; const chertogs = [ { id: "16.virgo", name: "Чертог Діви", start: [8, 27], end: [9, 20] }, { id: "1.boar", name: "Чертог Вепра", start: [9, 20], end: [10, 11] }, { id: "2.pike", name: "Чертог Щуки", start: [10, 11], end: [11, 3] }, { id: "3.swan", name: "Чертог Лебедя", start: [11, 3], end: [11, 24] }, { id: "4.snake", name: "Чертог Змія", start: [11, 24], end: [12, 16] }, { id: "5.crow", name: "Чертог Ворона", start: [12, 16], end: [1, 7] }, { id: "6.bear", name: "Чертог Ведмедя", start: [1, 7], end: [1, 31] }, { id: "7.stork", name: "Чертог Лелеки (Бусла)", start: [1, 31], end: [2, 25] }, { id: "8.wolf", name: "Чертог Вовка", start: [2, 25], end: [3, 22] }, { id: "9.fox", name: "Чертог Лисиці", start: [3, 22], end: [4, 14] }, { id: "10.bull", name: "Чертог Тура (Бика)", start: [4, 14], end: [5, 6] }, { id: "11.elk", name: "Чертог Лося", start: [5, 6], end: [5, 29] }, { id: "12.falcon", name: "Чертог Фініста (Сокола)", start: [5, 29], end: [6, 20] }, { id: "13.horse", name: "Чертог Коня", start: [6, 20], end: [7, 13] }, { id: "14.eagle", name: "Чертог Орла", start: [7, 13], end: [8, 4] }, { id: "15.white leopard", name: "Чертог Раса (білого леопарда)", start: [8, 4], end: [8, 27] } ]; function init() { const grid = document.getElementById("grid"); chertogs.forEach(c => { const item = document.createElement("div"); item.className = "chertog-item"; item.id = "item-" + c.id; item.onclick = () => openModal(c.id); const img = document.createElement("img"); img.className = "chertog-img"; img.src = "chertogs/" + c.id + ".webp"; img.alt = c.name; img.title = c.name; item.appendChild(img); grid.appendChild(item); }); } function isInChertog(m, d, c) { let sm = c.start[0], sd = c.start[1]; let em = c.end[0], ed = c.end[1]; if (sm === em) { return m === sm && d >= sd && d <= ed; } else if (sm < em) { if (m === sm && d >= sd) return true; if (m === em && d <= ed) return true; if (m > sm && m < em) return true; return false; } else { if (m === sm && d >= sd) return true; if (m === em && d <= ed) return true; if (m > sm || m < em) return true; return false; } } function calculateChertog() { const val = document.getElementById("birthDate").value; if (!val) return; const date = new Date(val); const m = date.getMonth() + 1; const d = date.getDate(); const activeIds = []; const activeNames = []; for (let i = 0; i < chertogs.length; i++) { const c = chertogs[i]; const el = document.getElementById("item-" + c.id); el.classList.remove("active"); if (isInChertog(m, d, c)) { activeIds.push(c.id); activeNames.push(c.name); el.classList.add("active"); setTimeout(() => { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); }, 100); } } const resultDiv = document.getElementById("result"); if (activeIds.length > 0) { if (activeIds.length > 1) { resultDiv.innerText = "Ви знаходитесь на межі: " + activeNames.join(" та "); } else { resultDiv.innerText = "Ваш чертог: " + activeNames[0]; } } else { resultDiv.innerText = ""; } } function openModal(id) { const modal = document.getElementById("modal"); const modalImg = document.getElementById("modalImg"); const modalText = document.getElementById("modalText"); modalImg.src = "chertogs/" + id + ".webp"; let desc = chertogDescriptions[id] || "Опис тимчасово недоступний."; desc = desc.replace(/\n\s*\n/g, '\n\n'); const godNames = { "1.boar": "Рамхата", "2.pike": "Рожани", "3.swan": "Макоші", "4.snake": "Семаргла", "5.crow": "Коляди", "6.bear": "Сварога", "7.stork": "Рода", "8.wolf": "Велеса", "9.fox": "Марени", "10.bull": "Кришеня", "11.elk": "Лади", "12.falcon": "Вишеня", "13.horse": "Купали", "14.eagle": "Перуна", "15.white leopard": "Тарха", "16.virgo": "Дживи" }; const chertogData = chertogs.find(c => c.id === id); modalText.textContent = desc; modal.classList.add("visible"); document.body.style.overflow = "hidden"; } function closeModal() { document.getElementById("modal").classList.remove("visible"); document.body.style.overflow = "auto"; } let bgMusic = null; const audioControl = document.getElementById('audioControl'); const audioIconOn = document.getElementById('audioIconOn'); const audioIconOff = document.getElementById('audioIconOff'); const TARGET_VOLUME = 0.4; const FADE_IN_DURATION = 2000; const FADE_OUT_DURATION = 1500; let audioStarted = false; let isMuted = false; let isPlaying = false; let fadeInterval = null; function fadeVolume(targetVolume, duration, callback) { if (!bgMusic) return; if (fadeInterval) { clearInterval(fadeInterval); fadeInterval = null; } const startVolume = bgMusic.volume || 0; const volumeDiff = targetVolume - startVolume; const steps = 60; const stepTime = duration / steps; let currentStep = 0; fadeInterval = setInterval(() => { currentStep++; const progress = currentStep / steps; const easeProgress = 1 - Math.pow(1 - progress, 3); bgMusic.volume = Math.max(0, Math.min(1, startVolume + volumeDiff * easeProgress)); if (currentStep >= steps) { clearInterval(fadeInterval); fadeInterval = null; bgMusic.volume = targetVolume; if (callback) callback(); } }, stepTime); } function startAudioOnFirstClick() { if (audioStarted) return; audioStarted = true; if (!bgMusic) { bgMusic = new Audio('slavetnodark.mp3'); bgMusic.loop = true; bgMusic.volume = 0; bgMusic.load(); } const playPromise = bgMusic.play(); if (playPromise !== undefined) { playPromise.then(() => { isPlaying = true; isMuted = false; fadeVolume(TARGET_VOLUME, FADE_IN_DURATION); updateAudioIcon(); document.removeEventListener('click', startAudioOnFirstClick, true); document.removeEventListener('touchend', startAudioOnFirstClick, true); document.removeEventListener('keydown', startAudioOnFirstClick, true); }).catch(err => { console.log('Audio playback failed:', err); audioStarted = false; }); } else { document.removeEventListener('click', startAudioOnFirstClick, true); document.removeEventListener('touchend', startAudioOnFirstClick, true); document.removeEventListener('keydown', startAudioOnFirstClick, true); } } document.addEventListener('click', startAudioOnFirstClick, true); document.addEventListener('touchend', startAudioOnFirstClick, true); document.addEventListener('keydown', startAudioOnFirstClick, true); if (audioControl) { audioControl.addEventListener('click', (e) => { e.stopPropagation(); if (!audioStarted) { startAudioOnFirstClick(); return; } isMuted = !isMuted; if (isMuted) { bgMusic.muted = true; audioControl.classList.add('muted'); audioIconOn.style.display = 'none'; audioIconOff.style.display = 'block'; } else { bgMusic.muted = false; audioControl.classList.remove('muted'); audioIconOn.style.display = 'block'; audioIconOff.style.display = 'none'; } }); } function updateAudioIcon() { if (isMuted) { audioControl.classList.add('muted'); audioIconOn.style.display = 'none'; audioIconOff.style.display = 'block'; } else { audioControl.classList.remove('muted'); audioIconOn.style.display = 'block'; audioIconOff.style.display = 'none'; } } window.onload = function () { if (typeof init === 'function') init(); flatpickr("#birthDate", { locale: { weekdays: { shorthand: ["Нд", "Пн", "Вт", "Ср", "Чт", "Пт", "Сб"], longhand: ["Неділя", "Понеділок", "Вівторок", "Середа", "Четвер", "П'ятниця", "Субота"] }, months: { shorthand: ["Січ", "Лют", "Бер", "Кві", "Тра", "Чер", "Лип", "Сер", "Вер", "Жов", "Лис", "Гру"], longhand: ["Січень", "Лютий", "Березень", "Квітень", "Травень", "Червень", "Липень", "Серпень", "Вересень", "Жовтень", "Листопад", "Грудень"] }, firstDayOfWeek: 1, rangeSeparator: " — ", weekAbbreviation: "Тиж.", scrollTitle: "Прокрутіть для збільшення", toggleTitle: "Натисніть для перемикання", amPM: ["ДП", "ПП"], yearAriaLabel: "Рік", monthAriaLabel: "Місяць", hourAriaLabel: "Година", minuteAriaLabel: "Хвилина", time_24hr: true }, dateFormat: "Y-m-d", altInput: true, altFormat: "d.m.Y", allowInput: true, disableMobile: true }); };